INSERT INTO classes (name, primary_ability, hit_die, saving_throw_proficiencies, skill_proficiencies, weapon_proficiencies, tool_proficiencies, armor_training, starting_equipment, becoming_text) VALUES ('Barbarian', 'Strength', 'D12 per Barbarian level', 'Strength and Constitution', 'Choose 2: Animal Handling, Athletics, Intimidation, Nature, Perception, or Survival', 'Simple and Martial weapons', NULL, 'Light and Medium armor and Shields', 'Choose A or B: (A) Greataxe, 4 Handaxes, Explorer\'s Pack, and 15 GP; or (B) 75 GP', '#### As a Level 1 Character

• Gain all the traits in the Core Barbarian Traits table.

• Gain the Barbarian\'s level 1 features, which are listed in the Barbarian Features table.

#### As a Multiclass Character

• Gain the following traits from the Core Barbarian Traits table: Hit Point Die, proficiency with Martial weapons, and training with Shields.
• Gain the Barbarian\'s level 1 features, which are listed in the Barbarian Features table.');
SET @class_id = LAST_INSERT_ID();
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 1, 'Rage', 'You can imbue yourself with a primal power called Rage, a force that grants you extraordinary might and resilience. You can enter it as a Bonus Action if you aren\'t wearing Heavy armor.

You can enter your Rage the number of times shown for your Barbarian level in the Rages column of the Barbarian Features table. You regain one expended use when you finish a Short Rest, and you regain all expended uses when you finish a Long Rest.

While active, your Rage follows the rules below.

_Damage Resistance._ You have Resistance to Bludgeoning, Piercing, and Slashing damage.

_Rage Damage._ When you make an attack using Strength—with either a weapon or an Unarmed Strike—and deal damage to the target, you gain a bonus to the damage that increases as you gain levels as a Barbarian, as shown in the Rage Damage column of the Barbarian Features table.

_Strength Advantage._ You have Advantage on Strength checks and Strength saving throws.

_No Concentration or Spells._ You can\'t maintain Concentration, and you can\'t cast spells.

_Duration._ The Rage lasts until the end of your next turn, and it ends early if you don Heavy armor or have the Incapacitated condition. If your Rage is still active on your next turn, you can extend the Rage for another round by doing one of the following:

- Make an attack roll against an enemy.
- Force an enemy to make a saving throw.
- Take a Bonus Action to extend your Rage.

Each time the Rage is extended, it lasts until the end of your next turn. You can maintain a Rage for up to 10 minutes.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 2, 'Unarmored Defense', 'While you aren\'t wearing any armor, your base Armor Class equals 10 plus your Dexterity and Constitution modifiers. You can use a Shield and still gain this benefit.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 3, 'Weapon Mastery', 'Your training with weapons allows you to use the mastery properties of two kinds of Simple or Martial Melee weapons of your choice, such as Greataxes and Handaxes. Whenever you finish a Long Rest, you can practice weapon drills and change one of those weapon choices.

When you reach certain Barbarian levels, you gain the ability to use the mastery properties of more kinds of weapons, as shown in the Weapon Mastery column of the Barbarian Features table.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 2, 4, 'Danger Sense', 'You gain an uncanny sense of when things aren\'t as they should be, giving you an edge when you dodge perils. You have Advantage on Dexterity saving throws unless you have the Incapacitated condition.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 2, 5, 'Reckless Attack', 'You can throw aside all concern for defense to attack with increased ferocity. When you make your first attack roll on your turn, you can decide to attack recklessly. Doing so gives you Advantage on attack rolls using Strength until the start of your next turn, but attack rolls against you have Advantage during that time.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 3, 6, 'Barbarian Subclass', 'You gain a Barbarian subclass of your choice. The Path of the Berserker subclass is detailed after this class\'s description. A subclass is a specialization that grants you features at certain Barbarian levels. For the rest of your career, you gain each of your subclass\'s features that are of your Barbarian level or lower.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 3, 7, 'Primal Knowledge', 'You gain proficiency in another skill of your choice from the skill list available to Barbarians at level 1.

In addition, while your Rage is active, you can channel primal power when you attempt certain tasks; whenever you make an ability check using one of the following skills, you can make it as a Strength check even if it normally uses a different ability: Acrobatics, Intimidation, Perception, Stealth, or Survival. When you use this ability, your Strength represents primal power coursing through you, honing your agility, bearing, and senses.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 4, 8, 'Ability Score Improvement', 'You gain the Ability Score Improvement feat (see "Feats") or another feat of your choice for which you qualify. You gain this feature again at Barbarian levels 8, 12, and 16.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 5, 9, 'Extra Attack', 'You can attack twice instead of once whenever you take the Attack action on your turn.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 5, 10, 'Fast Movement', 'Your speed increases by 10 feet while you aren\'t wearing Heavy armor.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 7, 11, 'Feral Instinct', 'Your instincts are so honed that you have Advantage on Initiative rolls.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 7, 12, 'Instinctive Pounce', 'As part of the Bonus Action you take to enter your Rage, you can move up to half your Speed.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 9, 13, 'Brutal Strike', 'If you use Reckless Attack, you can forgo any Advantage on one Strength-based attack roll of your choice on your turn. The chosen attack roll mustn\'t have Disadvantage. If the chosen attack roll hits, the target takes an extra 1d10 damage of the same type dealt by the weapon or Unarmed Strike, and you can cause one Brutal Strike effect of your choice. You have the following effect options.

_Forceful Blow._ The target is pushed 15 feet straight away from you. You can then move up to half your Speed straight toward the target without provoking Opportunity Attacks.
_Hamstring Blow._ The target\'s Speed is reduced by 15 feet until the start of your next turn. A target can be affected by only one Hamstring Blow at a time—the most recent one.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 11, 14, 'Relentless Rage', 'Your Rage can keep you fighting despite grievous wounds. If you drop to 0 Hit Points while your Rage is active and don\'t die outright, you can make a DC 10 Constitution saving throw. If you succeed, your Hit Points instead change to a number equal to twice your Barbarian level.

Each time you use this feature after the first, the DC increases by 5. When you finish a Short or Long Rest, the DC resets to 10.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 13, 15, 'Improved Brutal Strike', 'You have honed new ways to attack furiously. The following effects are now among your Brutal Strike options.

_Staggering Blow._ The target has Disadvantage on the next saving throw it makes, and it can\'t make Opportunity Attacks until the start of your next turn.

_Sundering Blow._ Before the start of your next turn, the next attack roll made by another creature against the target gains a +5 bonus to the roll. An attack roll can gain only one Sundering Blow bonus.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 15, 16, 'Persistent Rage', 'When you roll Initiative, you can regain all expended uses of Rage. After you regain uses of Rage in this way, you can\'t do so again until you finish a Long Rest.

In addition, your Rage is so fierce that it now lasts for 10 minutes without you needing to do anything to extend it from round to round. Your Rage ends early if you have the Unconscious condition (not just the Incapacitated condition) or don Heavy armor.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 17, 17, 'Improved Brutal Strike', 'The extra damage of your Brutal Strike increases to 2d10. In addition, you can use two different Brutal Strike effects whenever you use your Brutal Strike feature.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 18, 18, 'Indomitable Might', 'If your total for a Strength check or Strength saving throw is less than your Strength score, you can use that score in place of the total.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 19, 19, 'Epic Boon', 'You gain an Epic Boon feat (see "Feats") or another feat of your choice for which you qualify. Boon of Irresistible Offense is recommended.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 20, 20, 'Primal Champion', 'You embody primal power. Your Strength and Constitution scores increase by 4, to a maximum of 25.');
INSERT INTO subclasses (class_id, name, tagline, description) VALUES (@class_id, 'Path of the Berserker', 'Channel Rage into Violent Fury', 'Barbarians who walk the Path of the Berserker direct their Rage primarily toward violence. Their path is one of untrammeled fury, and they thrill in the chaos of battle as they allow their Rage to seize and empower them.');
SET @subclass_id = LAST_INSERT_ID();
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 3, 1, 'Frenzy', 'If you use Reckless Attack while your Rage is active, you deal extra damage to the first target you hit on your turn with a Strength-based attack. To determine the extra damage, roll a number of d6s equal to your Rage Damage bonus, and add them together. The damage has the same type as the weapon or Unarmed Strike used for the attack.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 6, 2, 'Mindless Rage', 'You have Immunity to the Charmed and Frightened conditions while your Rage is active. If you\'re Charmed or Frightened when you enter your Rage, the condition ends on you.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 10, 3, 'Retaliation', 'When you take damage from a creature that is within 5 feet of you, you can take a Reaction to make one melee attack against that creature, using a weapon or an Unarmed Strike.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 14, 4, 'Intimidating Presence', 'As a Bonus Action, you can strike terror into others with your menacing presence and primal power. When you do so, each creature of your choice in a 30-foot Emanation originating from you must make a Wisdom saving throw (DC 8 plus your Strength modifier and Proficiency Bonus). On a failed save, a creature has the Frightened condition for 1 minute. At the end of each of the Frightened creature\'s turns, the creature repeats the save, ending the effect on itself on a success.

Once you use this feature, you can\'t use it again until you finish a Long Rest unless you expend a use of your Rage (no action required) to restore your use of it.');
INSERT INTO classes (name, primary_ability, hit_die, saving_throw_proficiencies, skill_proficiencies, weapon_proficiencies, tool_proficiencies, armor_training, starting_equipment, becoming_text) VALUES ('Bard', 'Charisma', 'D8 per Bard level', 'Dexterity and Charisma', 'Choose any 3 skills (see Playing the Game)', 'Simple weapons', 'Choose 3 Musical Instruments (see Equipment)', 'Light armor', 'Choose A or B: (A) Leather Armor, 2 Daggers, Musical Instrument of your choice, Entertainer\'s Pack, and 19 GP; or (B) 90 GP', '#### As a Level 1 Character

• Gain all the traits in the Core Bard Traits table.

• Gain the Bard\'s level 1 features, which are listed in the Bard Features table.

#### As a Multiclass Character

• Gain the following traits from the Core Bard Traits table: Hit Point Die, proficiency in one skill of your choice, proficiency with one Musical Instrument of your choice, and training with Light armor.
• Gain the Bard\'s level 1 features, which are listed in the Bard Features table. See the multiclassing rules in "Character Creation" to determine your available spell slots.');
SET @class_id = LAST_INSERT_ID();
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 1, 'Bardic Inspiration', 'You can supernaturally inspire others through words, music, or dance. This inspiration is represented by your Bardic Inspiration die, which is a d6.

_Using Bardic Inspiration._ As a Bonus Action, you can inspire another creature within 60 feet of yourself who can see or hear you. That creature gains one of your Bardic Inspiration dice. A creature can have only one Bardic Inspiration die at a time.

Once within the next hour when the creature fails a D20 Test, the creature can roll the Bardic Inspiration die and add the number rolled to the d20, potentially turning the failure into a success. A Bardic Inspiration die is expended when it\'s rolled.

_Number of Uses._ You can confer a Bardic Inspiration die a number of times equal to your Charisma modifier (minimum of once), and you regain all expended uses when you finish a Long Rest.

_At Higher Levels._ Your Bardic Inspiration die changes when you reach certain Bard levels, as shown in the Bardic Die column of the Bard Features table. The die becomes a d8 at level 5, a d10 at level 10, and a d12 at level 15.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 2, 'Spellcasting', 'You have learned to cast spells through your bardic arts. See "Spells" for the rules on spellcasting. The information below details how you use those rules with Bard spells, which appear in the Bard spell list later in the class\'s description.

_Cantrips._ You know two cantrips of your choice from the Bard spell list. _Dancing Lights_ and _Vicious Mockery_ are recommended.

Whenever you gain a Bard level, you can replace one of your cantrips with another cantrip of your choice from the Bard spell list.

When you reach Bard levels 4 and 10, you learn another cantrip of your choice from the Bard spell list, as shown in the Cantrips column of the Bard Features table.

_Spell Slots._ The Bard Features table shows how many spell slots you have to cast your level 1+ spells. You regain all expended slots when you finish a Long Rest.

_Prepared Spells of Level 1+._ You prepare the list of level 1+ spells that are available for you to cast with this feature. To start, choose four level 1 spells from the Bard spell list. _Charm Person_, _Color Spray_, _Dissonant Whispers_, and _Healing Word_ are recommended.

The number of spells on your list increases as you gain Bard levels, as shown in the Prepared Spells column of the Bard Features table. Whenever that number increases, choose additional spells from the Bard spell list until the number of spells on your list matches the number on the table. The chosen spells must be of a level for which you have spell slots. For example, if you\'re a level 3 Bard, your list of prepared spells can include six spells of levels 1 and 2 in any combination.

If another Bard feature gives you spells that you always have prepared, those spells don\'t count against the number of spells you can prepare with this feature, but those spells otherwise count as Bard spells for you.

_Changing Your Prepared Spells._ Whenever you gain a Bard level, you can replace one spell on your list with another Bard spell for which you have spell slots.

_Spellcasting Ability._ Charisma is your spellcasting ability for your Bard spells.

_Spellcasting Focus._ You can use a Musical Instrument as a Spellcasting Focus for your Bard spells.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 2, 3, 'Expertise', 'You gain Expertise (see "Rules Glossary") in two of your skill proficiencies of your choice. Performance and Persuasion are recommended if you have proficiency in them.

At Bard level 9, you gain Expertise in two more of your skill proficiencies of your choice.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 2, 4, 'Jack of All Trades', 'You can add half your Proficiency Bonus (round down) to any ability check you make that uses a skill proficiency you lack and that doesn\'t otherwise use your Proficiency Bonus.

For example, if you make a Strength (Athletics) check and lack Athletics proficiency, you can add half your Proficiency Bonus to the check.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 3, 5, 'Bard Subclass', 'You gain a Bard subclass of your choice. The College of Lore subclass is detailed after this class\'s description. A subclass is a specialization that grants you features at certain Bard levels. For the rest of your career, you gain each of your subclass\'s features that are of your Bard level or lower.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 4, 6, 'Ability Score Improvement', 'You gain the Ability Score Improvement feat (see "Feats") or another feat of your choice for which you qualify. You gain this feature again at Bard levels 8, 12, and 16.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 5, 7, 'Font of Inspiration', 'You now regain all your expended uses of Bardic Inspiration when you finish a Short or Long Rest.

In addition, you can expend a spell slot (no action required) to regain one expended use of Bardic Inspiration.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 7, 8, 'Countercharm', 'You can use musical notes or words of power to disrupt mind-influencing effects. If you or a creature within 30 feet of you fails a saving throw against an effect that applies the Charmed or Frightened condition, you can take a Reaction to cause the save to be rerolled, and the new roll has Advantage.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 10, 9, 'Magical Secrets', 'You\'ve learned secrets from various magical traditions. Whenever you reach a Bard level (including this level) and the Prepared Spells number in the Bard Features table increases, you can choose any of your new prepared spells from the Bard, Cleric, Druid, and Wizard spell lists, and the chosen spells count as Bard spells for you (see a class\'s section for its spell list). In addition, whenever you replace a spell prepared for this class, you can replace it with a spell from those lists.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 18, 10, 'Superior Inspiration', 'When you roll Initiative, you regain expended uses of Bardic Inspiration until you have two if you have fewer than that.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 19, 11, 'Epic Boon', 'You gain an Epic Boon feat (see "Feats") or another feat of your choice for which you qualify. Boon of Spell Recall is recommended.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 20, 12, 'Words of Creation', 'You have mastered two of the Words of Creation: the words of life and death. You therefore always have the _Power Word Heal_ and _Power Word Kill_ spells prepared. When you cast either spell, you can target a second creature with it if that creature is within 10 feet of the first target.');
INSERT INTO subclasses (class_id, name, tagline, description) VALUES (@class_id, 'College of Lore', 'Plumb the Depths of Magical Knowledge', 'Bards of the College of Lore collect spells and secrets from diverse sources, such as scholarly tomes, mystical rites, and peasant tales. The college\'s members gather in libraries and universities to share their lore with one another. They also meet at festivals or affairs of state, where they can expose corruption, unravel lies, and poke fun at self-important figures of authority.');
SET @subclass_id = LAST_INSERT_ID();
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 3, 1, 'Bonus Proficiencies', 'You gain proficiency with three skills of your choice.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 3, 2, 'Cutting Words', 'You learn to use your wit to supernaturally distract, confuse, and otherwise sap the confidence and competence of others. When a creature that you can see within 60 feet of yourself makes a damage roll or succeeds on an ability check or attack roll, you can take a Reaction to expend one use of your Bardic Inspiration; roll your Bardic Inspiration die, and subtract the number rolled from the creature\'s roll, reducing the damage or potentially turning the success into a failure.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 6, 3, 'Magical Discoveries', 'You learn two spells of your choice. These spells can come from the Cleric, Druid, or Wizard spell list or any combination thereof (see a class\'s section for its spell list). A spell you choose must be a cantrip or a spell for which you have spell slots, as shown in the Bard Features table.

You always have the chosen spells prepared, and whenever you gain a Bard level, you can replace one of the spells with another spell that meets these requirements.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 14, 4, 'Peerless Skill', 'When you make an ability check or attack roll and fail, you can expend one use of Bardic Inspiration; roll the Bardic Inspiration die, and add the number rolled to the d20, potentially turning a failure into a success. On a failure, the Bardic Inspiration isn\'t expended.');
INSERT INTO classes (name, primary_ability, hit_die, saving_throw_proficiencies, skill_proficiencies, weapon_proficiencies, tool_proficiencies, armor_training, starting_equipment, becoming_text) VALUES ('Cleric', 'Wisdom', 'D8 per Cleric level', 'Wisdom and Charisma', 'Choose 2: History, Insight, Medicine, Persuasion, or Religion', 'Simple weapons', NULL, 'Light and Medium armor and Shields', 'Choose A or B: (A) Chain Shirt, Shield, Mace, Holy Symbol, Priest\'s Pack, and 7 GP; or (B) 110 GP', '#### As a Level 1 Character

- Gain all the traits in the Core Cleric Traits table.
- Gain the Cleric\'s level 1 features, which are listed in the Cleric Features table.

#### As a Multiclass Character

- Gain the following traits from the Core Cleric Traits table: Hit Point Die and training with Light and Medium armor and Shields.
- Gain the Cleric\'s level 1 features, which are listed in the Cleric Features table. See the multiclassing rules in "Character Creation" to determine your available spell slots.');
SET @class_id = LAST_INSERT_ID();
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 1, 'Spellcasting', 'You have learned to cast spells through prayer and meditation. See "Spells" for the rules on spellcasting. The information below details how you use those rules with Cleric spells, which appear on the Cleric spell list later in the class\'s description.

_Cantrips._ You know three cantrips of your choice from the Cleric spell list. _Guidance_, _Sacred Flame_, and _Thaumaturgy_ are recommended.

Whenever you gain a Cleric level, you can replace one of your cantrips with another cantrip of your choice from the Cleric spell list.

When you reach Cleric levels 4 and 10, you learn another cantrip of your choice from the Cleric spell list, as shown in the Cantrips column of the Cleric Features table.

_Spell Slots._ The Cleric Features table shows how many spell slots you have to cast your level 1+ spells. You regain all expended slots when you finish a Long Rest.

_Prepared Spells of Level 1+._ You prepare the list of level 1+ spells that are available for you to cast with this feature. To start, choose four level 1 spells from the Cleric spell list. _Bless_, _Cure Wounds_, _Guiding Bolt_, and _Shield of Faith_ are recommended.

The number of spells on your list increases as you gain Cleric levels, as shown in the Prepared Spells column of the Cleric Features table. Whenever that number increases, choose additional spells from the Cleric spell list until the number of spells on your list matches the number on the table. The chosen spells must be of a level for which you have spell slots. For example, if you\'re a level 3 Cleric, your list of prepared spells can include six spells of levels 1 and 2 in any combination.

If another Cleric feature gives you spells that you always have prepared, those spells don\'t count against the number of spells you can prepare with this feature, but those spells otherwise count as Cleric spells for you.

_Changing Your Prepared Spells._ Whenever you finish a Long Rest, you can change your list of prepared spells, replacing any of the spells there with other Cleric spells for which you have spell slots.

_Spellcasting Ability._ Wisdom is your spellcasting ability for your Cleric spells.

_Spellcasting Focus._ You can use a Holy Symbol as a Spellcasting Focus for your Cleric spells.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 2, 'Divine Order', 'You have dedicated yourself to one of the following sacred roles of your choice.

_Protector._ Trained for battle, you gain proficiency with Martial weapons and training with Heavy armor.

_Thaumaturge._ You know one extra cantrip from the Cleric spell list. In addition, your mystical connection to the divine gives you a bonus to your Intelligence (Arcana or Religion) checks. The bonus equals your Wisdom modifier (minimum of +1).');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 2, 3, 'Channel Divinity', 'You can channel divine energy directly from the Outer Planes to fuel magical effects. You start with two such effects: Divine Spark and Turn Undead, each of which is described below. Each time you use this class\'s Channel Divinity, choose which Channel Divinity effect from this class to create. You gain additional effect options at higher Cleric levels.

You can use this class\'s Channel Divinity twice. You regain one of its expended uses when you finish a Short Rest, and you regain all expended uses when you finish a Long Rest. You gain additional uses when you reach certain Cleric levels, as shown in the Channel Divinity column of the Cleric Features table.

If a Channel Divinity effect requires a saving throw, the DC equals the spell save DC from this class\'s Spellcasting feature.

_Divine Spark._ As a Magic action, you point your Holy Symbol at another creature you can see within 30 feet of yourself and focus divine energy at it. Roll 1d8 and add your Wisdom modifier. You either restore Hit Points to the creature equal to that total or force the creature to make a Constitution saving throw. On a failed save, the creature takes Necrotic or Radiant damage (your choice) equal to that total. On a successful save, the creature takes half as much damage (round down).

You roll an additional d8 when you reach Cleric levels 7 (2d8), 13 (3d8), and 18 (4d8).

_Turn Undead._ As a Magic action, you present your Holy Symbol and censure Undead creatures. Each Undead of your choice within 30 feet of you must make a Wisdom saving throw. If the creature fails its save, it has the Frightened and Incapacitated conditions for 1 minute. For that duration, it tries to move as far from you as it can on its turns. This effect ends early on the creature if it takes any damage, if you have the Incapacitated condition, or if you die.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 3, 4, 'Cleric Subclass', 'You gain a Cleric subclass of your choice. The Life Domain subclass is detailed after this class\'s description. A subclass is a specialization that grants you features at certain Cleric levels. For the rest of your career, you gain each of your subclass\'s features that are of your Cleric level or lower.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 4, 5, 'Ability Score Improvement', 'You gain the Ability Score Improvement feat (see "Feats") or another feat of your choice for which you qualify. You gain this feature again at Cleric levels 8, 12, and 16.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 5, 6, 'Sear Undead', 'Whenever you use Turn Undead, you can roll a number of d8s equal to your Wisdom modifier (minimum of 1d8) and add the rolls together. Each Undead that fails its saving throw against that use of Turn Undead takes Radiant damage equal to the roll\'s total. This damage doesn\'t end the turn effect.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 7, 7, 'Blessed Strikes', 'Divine power infuses you in battle. You gain one of the following options of your choice (if you get either option from a Cleric subclass in an older book, use only the option you choose for this feature).

_Divine Strike._ Once on each of your turns when you hit a creature with an attack roll using a weapon, you can cause the target to take an extra 1d8 Necrotic or Radiant damage (your choice).

_Potent Spellcasting._ Add your Wisdom modifier to the damage you deal with any Cleric cantrip.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 10, 8, 'Divine Intervention', 'You can call on your deity or pantheon to intervene on your behalf. As a Magic action, choose any Cleric spell of level 5 or lower that doesn\'t require a Reaction to cast. As part of the same action, you cast that spell without expending a spell slot or needing Material components. You can\'t use this feature again until you finish a Long Rest.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 14, 9, 'Improved Blessed Strikes', 'The option you chose for Blessed Strikes grows more powerful.

_Divine Strike._ The extra damage of your Divine Strike increases to 2d8.

_Potent Spellcasting._ When you cast a Cleric cantrip and deal damage to a creature with it, you can give vitality to yourself or another creature within 60 feet of yourself, granting a number of Temporary Hit Points equal to twice your Wisdom modifier.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 19, 10, 'Epic Boon', 'You gain an Epic Boon feat (see "Feats") or another feat of your choice for which you qualify. Boon of Fate is recommended.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 20, 11, 'Greater Divine Intervention', 'You can call on even more powerful divine intervention. When you use your Divine Intervention feature, you can choose _Wish_ when you select a spell. If you do so, you can\'t use Divine Intervention again until you finish 2d4 Long Rests.');
INSERT INTO subclasses (class_id, name, tagline, description) VALUES (@class_id, 'Life Domain', 'Soothe the Hurts of the World', 'The Life Domain focuses on the positive energy that helps sustain all life in the multiverse. Clerics who tap into this domain are masters of healing, using that life force to cure many hurts.

Existence itself relies on the positive energy associated with this domain, so a Cleric of almost any religious tradition might choose it. This domain is particularly associated with agricultural deities, gods of healing or endurance, and gods of home and community. Religious orders of healing also seek the magic of this domain.');
SET @subclass_id = LAST_INSERT_ID();
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 3, 1, 'Disciple of Life', 'When a spell you cast with a spell slot restores Hit Points to a creature, that creature regains additional Hit Points on the turn you cast the spell. The additional Hit Points equal 2 plus the spell slot\'s level.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 3, 2, 'Life Domain Spells', 'Your connection to this divine domain ensures you always have certain spells ready. When you reach a Cleric level specified in the Life Domain Spells table, you thereafter always have the listed spells prepared.

**Life Domain Spells**

<table>
  <thead>
    <tr>
      <th>Cleric Level</th>
      <th>Prepared Spells</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>3</td>
      <td>Aid, Bless, Cure Wounds, Lesser Restoration</td>
    </tr>
    <tr>
      <td>5</td>
      <td>Mass Healing Word, Revivify</td>
    </tr>
    <tr>
      <td>7</td>
      <td>Aura of Life, Death Ward</td>
    </tr>
    <tr>
      <td>9</td>
      <td>Greater Restoration, Mass Cure Wounds</td>
    </tr>
  </tbody>
</table>');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 3, 3, 'Preserve Life', 'As a Magic action, you present your Holy Symbol and expend a use of your Channel Divinity to evoke healing energy that can restore a number of Hit Points equal to five times your Cleric level. Choose Bloodied creatures within 30 feet of yourself (which can include you), and divide those Hit Points among them. This feature can restore a creature to no more than half its Hit Point maximum.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 6, 4, 'Blessed Healer', 'The healing spells you cast on others heal you as well. Immediately after you cast a spell with a spell slot that restores Hit Points to one or more creatures other than yourself, you regain Hit Points equal to 2 plus the spell slot\'s level.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 17, 5, 'Supreme Healing', 'When you would normally roll one or more dice to restore Hit Points to a creature with a spell or Channel Divinity, don\'t roll those dice for the healing; instead use the highest number possible for each die. For example, instead of restoring 2d6 Hit Points to a creature with a spell, you restore 12.');
INSERT INTO classes (name, primary_ability, hit_die, saving_throw_proficiencies, skill_proficiencies, weapon_proficiencies, tool_proficiencies, armor_training, starting_equipment, becoming_text) VALUES ('Druid', 'Wisdom', 'D8 per Druid level', 'Intelligence and Wisdom', 'Choose 2: Animal Handling, Arcana, Insight, Medicine, Nature, Perception, Religion, or Survival', 'Simple weapons', 'Herbalism Kit', 'Light armor and Shields', 'Choose A or B: (A) Leather Armor, Shield, Sickle, Druidic Focus (Quarterstaff), Explorer\'s Pack, Herbalism Kit, and 9 GP; or (B) 50 GP', '#### As a Level 1 Character

• Gain all the traits in the Core Druid Traits table.
• Gain the Druid\'s level 1 features, which are listed in the Druid Features table.

#### As a Multiclass Character

• Gain the following traits from the Core Druid Traits table: Hit Point Die and training with Light armor and Shields.
• Gain the Druid\'s level 1 features, which are listed in the Druid Features table. See the multiclassing rules in "Character Creation" to determine your available spell slots.');
SET @class_id = LAST_INSERT_ID();
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 1, 'Spellcasting', 'You have learned to cast spells through studying the mystical forces of nature. See "Spells" for the rules on spellcasting. The information below details how you use those rules with Druid spells, which appear on the Druid spell list later in the class\'s description.

_Cantrips._ You know two cantrips of your choice from the Druid spell list. _Druidcraft_ and _Produce Flame_ are recommended.

Whenever you gain a Druid level, you can replace one of your cantrips with another cantrip of your choice from the Druid spell list.

When you reach Druid levels 4 and 10, you learn another cantrip of your choice from the Druid spell list, as shown in the Cantrips column of the Druid Features table.

_Spell Slots._ The Druid Features table shows how many spell slots you have to cast your level 1+ spells. You regain all expended slots when you finish a Long Rest.

_Prepared Spells of Level 1+._ You prepare the list of level 1+ spells that are available for you to cast with this feature. To start, choose four level 1 spells from the Druid spell list. _Animal Friendship, Cure Wounds, Faerie Fire,_ and _Thunderwave_ are recommended.

The number of spells on your list increases as you gain Druid levels, as shown in the Prepared Spells column of the Druid Features table. Whenever that number increases, choose additional spells from the Druid spell list until the number of spells on your list matches the number on the table. The chosen spells must be of a level for which you have spell slots. For example, if you\'re a level 3 Druid, your list of prepared spells can include six spells of levels 1 and 2 in any combination.

If another Druid feature gives you spells that you always have prepared, those spells don\'t count against the number of spells you can prepare with this feature, but those spells otherwise count as Druid spells for you.

_Changing Your Prepared Spells._ Whenever you finish a Long Rest, you can change your list of prepared spells, replacing any of the spells with other Druid spells for which you have spell slots.

_Spellcasting Ability._ Wisdom is your spellcasting ability for your Druid spells.

_Spellcasting Focus._ You can use a Druidic Focus as a Spellcasting Focus for your Druid spells.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 2, 'Druidic', 'You know Druidic, the secret language of Druids. While learning this ancient tongue, you also unlocked the magic of communicating with animals; you always have the _Speak with Animals_ spell prepared.

You can use Druidic to leave hidden messages. You and others who know Druidic automatically spot such a message. Others spot the message\'s presence with a successful DC 15 Intelligence (Investigation) check but can\'t decipher it without magic.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 1, 3, 'Primal Order', 'You have dedicated yourself to one of the following sacred roles of your choice.

_Magician._ You know one extra cantrip from the Druid spell list. In addition, your mystical connection to nature gives you a bonus to your Intelligence (Arcana or Nature) checks. The bonus equals your Wisdom modifier (minimum bonus of +1).

_Warden._ Trained for battle, you gain proficiency with Martial weapons and training with Medium armor.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 2, 4, 'Wild Shape', 'The power of nature allows you to assume the form of an animal. As a Bonus Action, you shape-shift into a Beast form that you have learned for this feature (see "Known Forms" below). You stay in that form for a number of hours equal to half your Druid level or until you use Wild Shape again, have the Incapacitated condition, or die. You can also leave the form early as a Bonus Action.

_Number of Uses._ You can use Wild Shape twice. You regain one expended use when you finish a Short Rest, and you regain all expended uses when you finish a Long Rest.

You gain additional uses when you reach certain Druid levels, as shown in the Wild Shape column of the Druid Features table.

_Known Forms._ You know four Beast forms for this feature, chosen from among Beast stat blocks that have a maximum Challenge Rating of 1/4 and that lack a Fly Speed (see "Animals" in "Monsters" for stat block options). The **Rat**, **Riding Horse**, **Spider**, and **Wolf** are recommended. Whenever you finish a Long Rest, you can replace one of your known forms with another eligible form.

When you reach certain Druid levels, your number of known forms and the maximum Challenge Rating for those forms increases, as shown in the Beast Shapes table. In addition, starting at level 8, you can adopt a form that has a Fly Speed.

When choosing known forms, you may look in other sources for eligible Beasts if the Game Master permits you to do so.

**Beast Shapes**

<table>
  <thead>
    <tr>
      <th>Druid Level</th>
      <th>Known Forms</th>
      <th>Max CR</th>
      <th>Fly Speed</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>2</td>
      <td>4</td>
      <td>1/4</td>
      <td>No</td>
    </tr>
    <tr>
      <td>4</td>
      <td>6</td>
      <td>1/2</td>
      <td>No</td>
    </tr>
    <tr>
      <td>8</td>
      <td>8</td>
      <td>1</td>
      <td>Yes</td>
    </tr>
  </tbody>
</table>

**Rules While Shape-Shifted.** While in a form, you retain your personality, memories, and ability to speak, and the following rules apply:

**Temporary Hit Points.** When you assume a Wild Shape form, you gain a number of Temporary Hit Points equal to your Druid level.

**Game Statistics.** Your game statistics are replaced by the Beast\'s stat block, but you retain your creature type; Hit Points; Hit Point Dice; Intelligence, Wisdom, and Charisma scores; class features; languages; and feats. You also retain your skill and saving throw proficiencies and use your Proficiency Bonus for them, in addition to gaining the proficiencies of the creature. If a skill or saving throw modifier in the Beast\'s stat block is higher than yours, use the one in the stat block.

**No Spellcasting.** You can\'t cast spells, but shapeshifting doesn\'t break your Concentration or otherwise interfere with a spell you\'ve already cast.

**Objects.** Your ability to handle objects is determined by the form\'s limbs rather than your own. In addition, you choose whether your equipment falls in your space, merges into your new form, or is worn by it. Worn equipment functions as normal, but the GM decides whether it\'s practical for the new form to wear a piece of equipment based on the creature\'s size and shape. Your equipment doesn\'t change size or shape to match the new form, and any equipment that the new form can\'t wear must either fall to the ground or merge with the form. Equipment that merges with the form has no effect while you\'re in that form.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 2, 5, 'Wild Companion', 'You can summon a nature spirit that assumes an animal form to aid you. As a Magic action, you can expend a spell slot or a use of Wild Shape to cast the _Find Familiar_ spell without Material components.

When you cast the spell in this way, the familiar is Fey and disappears when you finish a Long Rest.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 3, 6, 'Druid Subclass', 'You gain a Druid subclass of your choice. The Circle of the Land subclass is detailed after this class\'s description. A subclass is a specialization that grants you features at certain Druid levels. For the rest of your career, you gain each of your subclass\'s features that are of your Druid level or lower.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 4, 7, 'Ability Score Improvement', 'You gain the Ability Score Improvement feat (see "Feats") or another feat of your choice for which you qualify. You gain this feature again at Druid levels 8, 12, and 16.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 5, 8, 'Wild Resurgence', 'Once on each of your turns, if you have no uses of Wild Shape left, you can give yourself one use by expending a spell slot (no action required).

In addition, you can expend one use of Wild Shape (no action required) to give yourself a level 1 spell slot, but you can\'t do so again until you finish a Long Rest.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 7, 9, 'Elemental Fury', 'The might of the elements flows through you. You gain one of the following options of your choice.

_Potent Spellcasting._ Add your Wisdom modifier to the damage you deal with any Druid cantrip.

_Primal Strike._ Once on each of your turns when you hit a creature with an attack roll using a weapon or a Beast form\'s attack in Wild Shape, you can cause the target to take an extra 1d8 Cold, Fire, Lightning, or Thunder damage (choose when you hit).');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 15, 10, 'Improved Elemental Fury', 'The option you chose for Elemental Fury grows more powerful, as detailed below.

_Potent Spellcasting._ When you cast a Druid cantrip with a range of 10 feet or greater, the spell\'s range increases by 300 feet.

_Primal Strike._ The extra damage of your Primal Strike increases to 2d8.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 18, 11, 'Beast Spells', 'While using Wild Shape, you can cast spells in Beast form, except for any spell that has a Material component with a cost specified or that consumes its Material component.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 19, 12, 'Epic Boon', 'You gain an Epic Boon feat (see "Feats") or another feat of your choice for which you qualify. Boon of Dimensional Travel is recommended.');
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, NULL, 20, 13, 'Archdruid', 'The vitality of nature constantly blooms within you, granting you the following benefits.

_Evergreen Wild Shape._ Whenever you roll Initiative and have no uses of Wild Shape left, you regain one expended use of it.

_Nature Magician._ You can convert uses of Wild Shape into a spell slot (no action required). Choose a number of your unexpended uses of Wild Shape and convert them into a single spell slot, with each use contributing 2 spell levels. For example, if you convert two uses of Wild Shape, you produce a level 4 spell slot. Once you use this benefit, you can\'t do so again until you finish a Long Rest.

_Longevity._ The primal magic that you wield causes you to age more slowly. For every ten years that pass, your body ages only one year.');
INSERT INTO subclasses (class_id, name, tagline, description) VALUES (@class_id, 'Circle of the Land', 'Celebrate Connection to the Natural World', 'The Circle of the Land comprises mystics and sages who safeguard ancient knowledge and rites. These Druids meet within sacred circles of trees or standing stones to whisper primal secrets in Druidic. The circle\'s wisest members preside as the chief priests of their communities.');
SET @subclass_id = LAST_INSERT_ID();
INSERT INTO class_features (class_id, subclass_id, level, sort_order, name, description) VALUES (@class_id, @subclass_id, 3, 1, 'Circle of the Land Spells', 'Whenever you finish a Long Rest, choose one type of land: arid, polar, temperate, or tropical. Consult the table below that corresponds to the chosen type; you have the spells listed for your Druid level and lower prepared.

**Arid Land**

<table>
  <thead>
    <tr>
      <th>Druid Level</th>
      <th>Circle Spells</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>3</td>
      <td>Blur, Burning Hands, Fire Bolt</td>
    </tr>
    <tr>
      <td>5</td>
      <td>Fireball</td>
    </tr>
    <tr>
      <td>7</td>
      <td>Blight</td>
    </tr>
    <tr>
      <td>9</td>
      <td>Wall of Stone</td>
    </tr>
  </tbody>
</table>

**Polar Land**

<table>
  <thead>
    <tr>
      <th>Druid Level</th>
      <th>Circle Spells</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>3</td>
      <td>Fog Cloud, Hold Person, Ray of Frost</td>
    </tr>
    <tr>
      <td>5</td>
      <td>Sleet Storm</td>
    </tr>
    <tr>
      <td>7</td>
      <td>Ice Storm</td>
    </tr>
    <tr>
      <td>9</td>
      <td>Cone of Cold</td>
    </tr>
  </tbody>
</table>

**Temperate Land**

<table>
  <thead>
    <tr>
      <th>Druid Level</th>
      <th>Circle Spells</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>3</td>
      <td>Misty Step, Shocking Grasp, Sleep</td>
    </tr>
    <tr>
      <td>5</td>
      <td>Lightning Bolt</td>
    </tr>
    <tr>
      <td>7</td>
      <td>Freedom of Movement</td>
    </tr>
    <tr>
      <td>9</td>
      <td>Tree Stride</td>
    </tr>
  </tbody>
</table>

**Tropical Land**

<table>
  <thead>
    <tr>
      <th>Druid Level</th>
      <th>Circle Spells</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>3</td>
      <td>Acid Splash, Ray of Sickness, Web</td>
    </tr>
