INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Bead of Force', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'This small black sphere measures 3/4 of an inch in diameter and weighs an ounce. Typically, 1d4 + 4 _Beads of Force_ are found together.

You can take a Magic action to throw the bead up to 60 feet. The bead explodes in a 10-foot-radius Sphere on impact and is destroyed. Each creature
in the Sphere must succeed on a DC 15 Dexterity saving throw or take 5d4 Force damage. A sphere of transparent force then encloses the area for 1 minute. Any creature that failed the save and is completely within the area is trapped inside this sphere. Creatures that succeeded on the save or are partially within the area are pushed away from the center of the sphere until they are no longer inside it. Only breathable air can pass through the sphere\'s wall. No attack or other effect can pass through.

An enclosed creature can take a Utilize action to push against the sphere\'s wall, moving the sphere up to half the creature\'s Speed. The sphere can be picked up, and its magic causes it to weigh only 1 pound, regardless of the weight of creatures inside.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Bead of Nourishment', 'Wondrous Item', NULL, 'Common', 0, NULL, 'This flavorless, gelatinous bead dissolves on your tongue and provides as much nourishment as 1 day of Rations.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Belt of Dwarvenkind', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While wearing this belt, you gain the following benefits:

**Dwarvish.** You know Dwarvish.

**Friend of Dwarvenkind.** You have Advantage on Charisma (Persuasion) checks made to interact with dwarves and duergar.

**Toughness.** Your Constitution increases by 2, to a maximum of 20.

In addition, while attuned to the belt, you have a 50 percent chance each day at dawn of growing a full beard if you can grow one, or a thicker beard if you already have one.

If you aren\'t a dwarf or duergar, you gain the following additional benefits while wearing the belt:

**Darkvision.** You have Darkvision with a range of 60 feet.

**Resilience.** You have Resistance to Poison damage. You also have Advantage on saving throws you make to avoid or end the Poisoned condition.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Belt of Giant Strength', 'Wondrous Item', NULL, 'Rarity Varies (Requires Attunement)', 1, NULL, 'While wearing this belt, your Strength changes to a score granted by the belt. The type of giant determines the score (see the table below). The item has no effect on you if your Strength without the belt is equal to or greater than the belt\'s score.

<table>
  <thead>
    <tr>
      <th>Belt</th>
      <th>Str.</th>
      <th>Rarity</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>Belt of Giant Strength (hill)</td>
      <td>21</td>
      <td>Rare</td>
    </tr>
    <tr>
      <td>Belt of Giant Strength (frost or stone)</td>
      <td>23</td>
      <td>Very Rare</td>
    </tr>
    <tr>
      <td>Belt of Giant Strength (fire)</td>
      <td>25</td>
      <td>Very Rare</td>
    </tr>
    <tr>
      <td>Belt of Giant Strength (cloud)</td>
      <td>27</td>
      <td>Legendary</td>
    </tr>
    <tr>
      <td>Belt of Giant Strength (storm)</td>
      <td>29</td>
      <td>Legendary</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Berserker Axe', 'Weapon', 'Battleaxe, Greataxe, or Halberd', 'Rare (Requires Attunement)', 1, NULL, 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon. In addition, while you are attuned to this weapon, your Hit Point maximum increases by 1 for each level you have attained.

_Curse._ This weapon is cursed, and becoming attuned to it extends the curse to you. As long as you remain cursed, you are unwilling to part with the weapon, keeping it within reach at all times. You also have Disadvantage on attack rolls with weapons other than this one.

Whenever another creature damages you while the weapon is in your possession, you must succeed on a DC 15 Wisdom saving throw or go berserk. This berserk state ends when you start your turn and there are no creatures within 60 feet of you that you can see or hear.

While berserk, you regard the creature nearest to you that you can see or hear as your enemy. If there are multiple possible creatures, choose one at random. On each of your turns, you must move as close to the creature as possible and take the Attack action, targeting the creature. If you\'re unable to get close enough to the creature to attack it with the weapon, your turn ends after you\'ve used up all your available movement. If the creature dies or can no longer be seen or heard by you, the next nearest creature that you can see or hear becomes your new target.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Boots of Elvenkind', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, 'While you wear these boots, your steps make no sound, regardless of the surface you are moving across. You also have Advantage on Dexterity (Stealth) checks.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Boots of Levitation', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While you wear these boots, you can cast _Levitate_ on yourself.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Boots of Speed', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While you wear these boots, you can take a Bonus Action to click the boots\' heels together. If you do, the boots double your Speed, and any creature that makes an Opportunity Attack against you has Disadvantage on the attack roll. If you click your heels together again, you end the effect.

When you\'ve used the boots\' property for a total of 10 minutes, the magic ceases to function for you until you finish a Long Rest.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Boots of Striding and Springing', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While you wear these boots, your Speed becomes 30 feet unless your Speed is higher, and your Speed isn\'t reduced by you carrying weight in excess of your carrying capacity or wearing Heavy Armor.

Once on each of your turns, you can jump up to 30 feet by spending only 10 feet of movement.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Boots of the Winterlands', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'These furred boots are snug and feel warm. While wearing them, you gain the following benefits.

_Cold Resistance._ You have Resistance to Cold damage and can tolerate temperatures of 0 degrees Fahrenheit or lower without any additional protection.

_Winter Strider._ You ignore Difficult Terrain created by ice or snow.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Bowl of Commanding Water Elementals', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'While this bowl is filled with water and you are within 5 feet of it, you can take a Magic action to summon a Water Elemental. The elemental appears in an unoccupied space as close to the bowl as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The bowl can\'t be used this way again until the next dawn.

The bowl is about 1 foot in diameter and half as deep. It holds about 3 gallons.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Bracers of Archery', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While wearing these bracers, you have proficiency with the Longbow and Shortbow, and you gain a +2 bonus to damage rolls made with such weapons.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Bracers of Defense', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While wearing these bracers, you gain a +2 bonus to Armor Class if you are wearing no armor and using no Shield.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Brazier of Commanding Fire Elementals', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'While you are within 5 feet of this brazier, you can take a Magic action to summon a Fire Elemental. The elemental appears in an unoccupied space as close to the brazier as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The brazier can\'t be used this way again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Brooch of Shielding', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While wearing this brooch, you have Resistance to Force damage, and you have Immunity to damage from the _Magic Missile_ spell.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Broom of Flying', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'This wooden broom functions like a mundane broom until you stand astride it and take a Magic action to make it hover beneath you, at which time it can be ridden in the air. It has a Fly Speed of 50 feet. It can carry up to 400 pounds, but its Fly Speed becomes 30 feet while carrying over 200 pounds. The broom stops hovering when you land or when you\'re no longer riding it.

As a Magic action, you can send the broom to travel alone to a destination within 1 mile of you if you name the location and are familiar with it. The broom comes back to you when you take a Magic action and use a command word if the broom is still within 1 mile of you.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Candle of Invocation', 'Wondrous Item', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'This candle\'s magic is activated when the candle is lit, which requires a Magic action. After burning for 4 hours, the candle is destroyed. You can snuff it out early for use at a later time. Deduct the time it burned in increments of 1 minute from its total burn time.

While lit, the candle sheds Dim Light in a 30-foot radius. While you are within that light, you have Advantage on D20 Tests. In addition, a Cleric or Druid in the light can cast level 1 spells they have prepared without expending spell slots.

Alternatively, when you light the candle for the first time, you can cast _Gate_ with it. Doing so destroys the candle. The portal created by the spell
links to a particular Outer Plane chosen by the GM or determined by rolling on the following table.

<table>
  <thead>
    <tr>
      <th>1d100</th>
      <th>Outer Plane</th>
      <th>1d100</th>
      <th>Outer Plane</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>01–05</td>
      <td>Abyss</td>
      <td>55–59</td>
      <td>Gehenna</td>
    </tr>
    <tr>
      <td>06–10</td>
      <td>Acheron</td>
      <td>60–64</td>
      <td>Hades</td>
    </tr>
    <tr>
      <td>11–17</td>
      <td>Arborea</td>
      <td>65–69</td>
      <td>Limbo</td>
    </tr>
    <tr>
      <td>18–25</td>
      <td>Arcadia</td>
      <td>70–77</td>
      <td>Mechanus</td>
    </tr>
    <tr>
      <td>26–33</td>
      <td>Beastlands</td>
      <td>78–85</td>
      <td>Mount Celestia</td>
    </tr>
    <tr>
      <td>34–41</td>
      <td>Bytopia</td>
      <td>86–90</td>
      <td>Nine Hells</td>
    </tr>
    <tr>
      <td>42–46</td>
      <td>Carceri</td>
      <td>91–95</td>
      <td>Pandemonium</td>
    </tr>
    <tr>
      <td>47–54</td>
      <td>Elysium</td>
      <td>96–00</td>
      <td>Ysgard</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cape of the Mountebank', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'This cape smells faintly of brimstone. While wearing it, you can use it to cast _Dimension Door_ as a Magic action. This property can\'t be used again until the next dawn.

When you teleport with that spell, you leave behind a cloud of smoke. The space you left is Lightly Obscured by that smoke until the end of your next turn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Carpet of Flying', 'Wondrous Item', NULL, 'Very Rare', 0, NULL, 'You can make this carpet hover and fly by taking a Magic action and using the carpet\'s command word. It moves according to your directions if you are within 30 feet of it.

Four sizes of _Carpet of Flying_ exist. The GM chooses the size of a given carpet or determines it randomly by rolling on the following table. A carpet can carry up to twice the weight shown on the table, but its Fly Speed is halved if it carries more than its normal capacity.

<table>
  <thead>
    <tr>
      <th>1d100</th>
      <th>Size</th>
      <th>Capacity</th>
      <th>Fly Speed</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>01–20</td>
      <td>3 ft. × 5 ft.</td>
      <td>200 lb.</td>
      <td>80 feet</td>
    </tr>
    <tr>
      <td>21–55</td>
      <td>4 ft. × 6 ft.</td>
      <td>400 lb.</td>
      <td>60 feet</td>
    </tr>
    <tr>
      <td>56–80</td>
      <td>5 ft. × 7 ft.</td>
      <td>600 lb.</td>
      <td>40 feet</td>
    </tr>
    <tr>
      <td>81–00</td>
      <td>6 ft. × 9 ft.</td>
      <td>800 lb.</td>
      <td>30 feet</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Censer of Controlling Air Elementals', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'While gently swinging this censer, you can take a Magic action to summon an Air Elemental. The elemental appears in an unoccupied space as close to the censer as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The censer can\'t be used this way again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Chime of Opening', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'This hollow metal tube measures about 1 foot long and weighs 1 pound. As a Magic action, you can strike the chime to cast _Knock_. The spell\'s customary knocking sound is replaced by the clear, ringing tone of the chime, which is audible out to 300 feet.

The chime can be used 10 times. After the tenth time, it cracks and becomes useless.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Circlet of Blasting', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, 'While wearing this circlet, you can cast _Scorching Ray_ with it (+5 to hit). The circlet can\'t cast this spell again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cloak of Arachnida', 'Wondrous Item', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'This fine garment is made of black silk interwoven with faint, silvery threads. While wearing it, you gain the following benefits.

_Poison Resistance._ You have Resistance to Poison damage.

_Spider Climb._ You have a Climb Speed equal to your Speed and can move up, down, and across vertical surfaces and along ceilings, while leaving your hands free.

_Spider Walk._ You can\'t be caught in webs of any sort and can move through webs as if they were Difficult Terrain.

_Web._ You can cast _Web_ (save DC 13). The web created by the spell fills twice its normal area. Once used, this property can\'t be used again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cloak of Displacement', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While you wear this cloak, it magically projects an illusion that makes you appear to be standing in a place near your actual location, causing any creature to have Disadvantage on attack rolls against you. If you take damage, the property ceases to function until the start of your next turn. This property is suppressed while your Speed is 0.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cloak of Elvenkind', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While you wear this cloak, Wisdom (Perception) checks made to perceive you have Disadvantage, and you have Advantage on Dexterity (Stealth) checks.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cloak of Invisibility', 'Wondrous Item', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'This cloak has 3 charges and regains 1d3 expended charges daily at dawn. While wearing the cloak, you can take a Magic action to pull its hood over your
head and expend 1 charge to give yourself the Invisible condition for 1 hour. The effect ends early if you pull the hood down (no action required) or cease wearing the cloak.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cloak of Protection', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'You gain a +1 bonus to Armor Class and saving throws while you wear this cloak.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cloak of the Bat', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While wearing this cloak, you have Advantage on Dexterity (Stealth) checks. In an area of Dim Light or Darkness, you can grip the edges of the cloak and use it to gain a Fly Speed of 40 feet. If you ever fail to grip the cloak\'s edges while flying in this way, or if you are no longer in Dim Light or Darkness, you lose this Fly Speed.

While wearing the cloak in an area of Dim Light or Darkness, you can cast _Polymorph_ on yourself, shape-shifting into a Bat. While in that form, you retain your Intelligence, Wisdom, and Charisma scores. The cloak can\'t be used this way again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cloak of the Manta Ray', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While wearing this cloak, you can breathe underwater, and you have a Swim Speed of 60 feet.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Crystal Ball', 'Wondrous Item', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'While touching this crystal orb, you can cast _Scrying_ (save DC 17) with it.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Crystal Ball of Mind Reading', 'Wondrous Item', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'While touching this crystal orb, you can cast _Scrying_ (save DC 17) with it. In addition, you can cast _Detect Thoughts_ (save DC 17) targeting creatures you can see within 30 feet of the spell\'s sensor. You don\'t need to concentrate on this _Detect Thoughts_ spell to maintain it during its duration, but it ends if the _Scrying_ spell ends.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Crystal Ball of Telepathy', 'Wondrous Item', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'While touching this crystal orb, you can cast _Scrying_ (save DC 17) with it. In addition, you can communicate telepathically with creatures you can see within 30 feet of the spell\'s sensor. You can also cast _Suggestion_ (save DC 17) through the sensor on one of those creatures. You don\'t need to concentrate on this _Suggestion_ to maintain it during its duration, but it ends if _Scrying_ ends. You can\'t cast _Suggestion_ in this way again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Crystal Ball of True Seeing', 'Wondrous Item', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'While touching this crystal orb, you can cast _Scrying_ (save DC 17) with it. In addition, you have Truesight with a range of 120 feet centered on the spell\'s sensor.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cube of Force', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This cube is about an inch across. Each face has a distinct marking on it. You can press one of those faces, expend the number of charges required for it, and thereby cast the spell associated with it (save DC 17), as shown in the Cube of Force Faces table.

The cube starts with 10 charges, and it regains 1d6 expended charges daily at dawn.

**Cube of Force Faces**

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>Mage Armor</td>
      <td>1</td>
    </tr>
    <tr>
      <td>Shield</td>
      <td>1</td>
    </tr>
    <tr>
      <td>Tiny Hut</td>
      <td>3</td>
    </tr>
    <tr>
      <td>Private Sanctum</td>
      <td>4</td>
    </tr>
    <tr>
      <td>Resilient Sphere</td>
      <td>4</td>
    </tr>
    <tr>
      <td>Wall of Force</td>
      <td>5</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Cubic Gate', 'Wondrous Item', NULL, 'Legendary', 0, NULL, 'This cube is 3 inches across and radiates palpable magical energy. The six sides of the cube are each keyed to a different plane of existence, one of which is the Material Plane. The other sides are linked to planes determined by the GM.

The cube has 3 charges and regains 1d3 expended charges daily at dawn. As a Magic action, you can expend 1 of the cube\'s charges to cast one of the following spells using the cube.

_Gate._ Pressing one side of the cube, you cast _Gate_, opening a portal to the plane of existence keyed to that side.

_Plane Shift._ Pressing one side of the cube twice, you cast _Plane Shift_, transporting the targets to the plane of existence keyed to that side.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Dagger of Venom', 'Weapon', 'Dagger', 'Rare', 0, NULL, 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon.

You can take a Bonus Action to magically coat the blade with poison. The poison remains for 1 minute or until an attack using this weapon hits a creature. That creature must succeed on a DC 15 Constitution saving throw or take 2d10 Poison damage and have the Poisoned condition for 1 minute. The weapon can\'t be used this way again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Dancing Sword', 'Weapon', 'Greatsword, Longsword, Rapier, Scimitar, or Shortsword', 'Very Rare (Requires Attunement)', 1, NULL, 'You can take a Bonus Action to toss this magic weapon into the air. When you do so, the weapon begins to hover, flies up to 30 feet, and attacks one creature of your choice within 5 feet of itself. The weapon uses your attack roll and adds your ability modifier to damage rolls.

While the weapon hovers, you can take a Bonus Action to cause it to fly up to 30 feet to another spot within 30 feet of you. As part of the same Bonus Action, you can cause the weapon to attack one creature within 5 feet of the weapon.

After the hovering weapon attacks for the fourth time, it flies back to you and tries to return to your hand. If you have no hand free, the weapon falls to the ground in your space. If the weapon has no unobstructed path to you, it moves as close to you as it can and then falls to the ground. It also ceases to hover if you grasp it or are more than 30 feet away from it.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Decanter of Endless Water', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, 'This stoppered flask sloshes when shaken, as if it contains water. The decanter weighs 2 pounds.

You can take a Magic action to remove the stopper and issue one of three command words, whereupon an amount of fresh water or salt water (your choice) pours out of the flask. The water stops pouring out at the start of your next turn. Choose from the following command words:

**Splash.** The decanter produces 1 gallon of water.
**Fountain.** The decanter produces 5 gallons of water.
**Geyser.** The decanter produces 30 gallons of water that gushes forth in a Line 30 feet long and 1 foot wide. If you\'re holding the decanter, you can aim the geyser in one direction (no action required). One creature of your choice in the Line must succeed on a DC 13 Strength saving throw or take 1d4 Bludgeoning damage and have the Prone condition. Instead of a creature, you can target one object in the Line that isn\'t being worn or carried and that weighs no more than 200 pounds. The object is knocked over by the geyser.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Deck of Illusions', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, 'This box contains a set of cards. A full deck has 34 cards: 32 depicting specific creatures and two with a mirrored surface. A deck found as treasure is usually missing 1d20 − 1 cards.

The magic of the deck functions only if its cards are drawn at random. You can take a Magic action to draw a card at random from the deck and throw it to the ground at a point within 30 feet of yourself. An illusion of a creature, determined by rolling on the Deck of Illusions table, forms over the thrown card and remains until dispelled. The illusory creature created by the card looks and behaves like a real creature of its kind, except that it can do no harm. While you are within 120 feet of the illusory creature and can see it, you can take a Magic action to move it anywhere within 30 feet of its card.

Any physical interaction with the illusory creature reveals it to be false, because objects pass through it. A creature that takes a Study action to visually inspect the illusory creature identifies it as an illusion with a successful DC 15 Intelligence (Investigation) check. The illusion lasts until its card is moved or the illusion is dispelled (using a _Dispel Magic_ spell or a similar effect). When the illusion ends, the image on its card disappears, and that card can\'t be used again.

**Deck of Illusions**

