      <td>+1</td>
      <td>+1</td>
      <td>CON</td>
      <td>13</td>
      <td>+1</td>
      <td>+1</td>
    </tr>
    <tr>
      <td>INT</td>
      <td>2</td>
      <td>−4</td>
