INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Nine Lives Stealer', 'Weapon', 'Any Simple or Martial', 'Very Rare (Requires Attunement)', 1, NULL, 'You gain a +2 bonus to attack rolls and damage rolls made with this magic weapon.

**_Life Stealing._** The weapon has 1d8 + 1 charges. When you attack a creature that has fewer than 100 Hit Points with this weapon and roll a 20 on the d20 for the attack roll, the creature must succeed on a DC 15 Constitution saving throw or be slain instantly as the sword tears its life force from its body. Constructs and Undead succeed on the save automatically. The weapon loses 1 charge if the creature is slain. When the weapon has no charges remaining, it loses this property.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Oathbow', 'Weapon', 'Longbow or Shortbow', 'Very Rare (Requires Attunement)', 1, NULL, 'When you nock an arrow on this bow, it whispers in Elvish, "Swift defeat to my enemies." When you use this weapon to make a ranged attack, you can utter or sign the following command words: "Swift death to you who have wronged me." The target of your attack becomes your sworn enemy until it dies or until dawn 7 days later. You can have only one such sworn enemy at a time. When your sworn enemy dies, you can choose a new one after the next dawn.

When you make a ranged attack roll with this weapon against your sworn enemy, you have Advantage on the roll. In addition, your target gains no benefit from Half Cover or Three-Quarters Cover, and you suffer no Disadvantage due to long range. If the attack hits, your sworn enemy takes an extra 3d6 Piercing damage.

While your sworn enemy lives, you have Disadvantage on attack rolls with all other weapons.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Oil of Etherealness', 'Potion', NULL, 'Rare', 0, NULL, 'One vial of this oil can cover one Medium or smaller creature, along with the equipment it\'s wearing and carrying (one additional vial is required for each size category above Medium). Applying the oil takes 10 minutes. The affected creature then gains the effect of the _Etherealness_ spell for 1 hour.

Beads of this cloudy, gray oil form on the outside of its container and quickly evaporate.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Oil of Sharpness', 'Potion', NULL, 'Very Rare', 0, NULL, 'One vial of this oil can coat one Melee weapon or twenty pieces of ammunition, but only ammunition and Melee weapons that are nonmagical and deal Slashing or Piercing damage are affected. Applying the oil takes 1 minute, after which the oil magically seeps into whatever it coats, turning the coated weapon into a _+3 Weapon_ or the coated ammunition into _+3 Ammunition_.

This clear, gelatinous oil sparkles with tiny, ultrathin silver shards.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Oil of Slipperiness', 'Potion', NULL, 'Uncommon', 0, NULL, 'One vial of this oil can cover one Medium or smaller creature, along with the equipment it\'s wearing and carrying (one additional vial is required for each size category above Medium). Applying the oil takes 10 minutes. The affected creature then gains the effect of the _Freedom of Movement_ spell for 8 hours.

Alternatively, the oil can be poured on the ground as a Magic action, where it covers a 10-foot square, duplicating the effect of the _Grease_ spell in that area for 8 hours.

This sticky, black unguent is thick and heavy, but it flows quickly when poured.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Pearl of Power', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement by a Spellcaster)', 1, 'by a Spellcaster', 'While this pearl is on your person, you can take a Magic action to regain one expended spell slot of level 3 or lower. Once you use the pearl, it can\'t be used again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Periapt of Health', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While wearing this pendant, you can take a Magic action to regain 2d4 + 2 Hit Points. Once used, this property can\'t be used again until the next dawn.

In addition, you have Advantage on saving throws to avoid or end the Poisoned condition while you wear this pendant.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Periapt of Proof against Poison', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This delicate silver chain has a brilliant-cut black gem pendant. While you wear it, you have Immunity to the Poisoned condition and Poison damage.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Periapt of Wound Closure', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While wearing this pendant, you gain the following benefits.

**_Life Preservation._** Whenever you make a Death Saving Throw, you can change a roll of 9 or lower to a 10, turning a failed save into a successful one.

**_Natural Healing Boost._** Whenever you roll a Hit Point Die to regain Hit Points, double the number of Hit Points it restores.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Philter of Love', 'Potion', NULL, 'Uncommon', 0, NULL, 'The next time you see a creature within 10 minutes after drinking this philter, you are charmed by that creature and have the Charmed condition for 1 hour.

This rose-hued, effervescent liquid contains one easy-to-miss bubble shaped like a heart.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Pipes of Haunting', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, 'These pipes have 3 charges and regain 1d3 expended charges daily at dawn. You can take a Magic action to play them and expend 1 charge to create an eerie, spellbinding tune. Each creature of your choice within 30 feet of you must succeed on a DC 15 Wisdom saving throw or have the Frightened condition for 1 minute. A creature that fails the save repeats it at the end of each of its turns, ending the effect on itself on a success. A creature that succeeds on its save is immune to the effect of these pipes for 24 hours.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Pipes of the Sewers', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While these pipes are on your person, ordinary rats and giant rats are Indifferent toward you and won\'t attack you unless you threaten or harm them.

The pipes have 3 charges and regain 1d3 expended charges daily at dawn. If you play the pipes as a Magic action, you can take a Bonus Action to expend 1 to 3 charges, calling forth one Swarm of Rats with each expended charge if enough rats are within half a mile of you to be called in this fashion (as determined by the GM). If there aren\'t enough rats to form a swarm, the charge is wasted. Called swarms move toward the music by the shortest available route but aren\'t under your control otherwise.

Whenever a Swarm of Rats that isn\'t under another creature\'s control comes within 30 feet of you while you are playing the pipes, the swarm makes a DC 15 Wisdom saving throw. On a successful save, the swarm behaves as it normally would and can\'t be swayed by the pipes\' music for the next 24 hours. On a failed save, the swarm is swayed by the pipes\' music and becomes Friendly to you and your allies for as long as you continue to play the pipes each round as a Magic action. A Friendly swarm obeys your commands. If you issue no commands to a Friendly swarm, it defends itself but otherwise takes no actions. If a Friendly swarm starts its turn more than 30 feet away from you, your control over that swarm ends, and the swarm behaves as it normally would and can\'t be swayed by the pipes\' music for the next 24 hours.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Plate Armor of Etherealness', 'Armor', 'Half Plate Armor or Plate Armor', 'Legendary (Requires Attunement)', 1, NULL, 'While you\'re wearing this armor, you can take a Magic action and use a command word to gain the effect of the _Etherealness_ spell. The spell ends immediately if you remove the armor or take a Magic action to repeat the command word. This property of the armor can\'t be used again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Portable Hole', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'This fine black cloth, soft as silk, is folded up to the dimensions of a handkerchief. It unfolds into a circular sheet 6 feet in diameter.

You can take a Magic action to unfold a _Portable Hole_ and place it on or against a solid surface, whereupon the _Portable Hole_ creates an
extradimensional hole 10 feet deep. The cylindrical space within the hole exists on a different plane of existence, so it can\'t be used to create open passages. Any creature inside an open _Portable Hole_ can exit the hole by climbing out of it.

You can take a Magic action to close a _Portable Hole_ by taking hold of the edges of the cloth and folding it up. Folding the cloth closes the hole, and any creatures or objects within remain in the extradimensional space. No matter what\'s in it, the hole weighs next to nothing.

If the hole is folded up, a creature within the hole\'s extradimensional space can take an action to make a DC 10 Strength (Athletics) check. On a successful check, the creature forces its way out and appears within 5 feet of the _Portable Hole_. A closed _Portable Hole_ holds enough air for 1 hour of breathing, divided by the number of breathing creatures inside.

Placing a _Portable Hole_ inside an extradimensional space created by a _Bag of Holding_, _Handy Haversack_, or similar item instantly destroys both items and opens a gate to the Astral Plane. The gate originates where the one item was placed inside the other. Any creature within 10 feet of the gate and not behind Total Cover is sucked through it and deposited in a random location on the Astral Plane. The gate then closes. The gate is one-way only and can\'t be reopened.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Animal Friendship', 'Potion', NULL, 'Uncommon', 0, NULL, 'When you drink this potion, you can cast the level 3 version of the _Animal Friendship_ spell (save DC 13).

Agitating this potion\'s muddy liquid brings little bits into view: a fish scale, a hummingbird feather, a cat claw, or a squirrel hair.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Clairvoyance', 'Potion', NULL, 'Rare', 0, NULL, 'When you drink this potion, you gain the effect of the _Clairvoyance_ spell (no Concentration required).

An eyeball bobs in this potion\'s yellowish liquid but vanishes when the potion is opened.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Climbing', 'Potion', NULL, 'Common', 0, NULL, 'When you drink this potion, you gain a Climb Speed equal to your Speed for 1 hour. During this time, you have Advantage on Strength (Athletics) checks to climb.

This potion is separated into brown, silver, and gray layers resembling bands of stone. Shaking the bottle fails to mix the colors.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Diminution', 'Potion', NULL, 'Rare', 0, NULL, 'When you drink this potion, you gain the "reduce" effect of the _Enlarge/Reduce_ spell for 1d4 hours (no Concentration required).

The red in the potion\'s liquid continuously contracts to a tiny bead and then expands to color the clear liquid around it. Shaking the bottle fails to interrupt this process.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Flying', 'Potion', NULL, 'Very Rare', 0, NULL, 'When you drink this potion, you gain a Fly Speed equal to your Speed for 1 hour and can hover. If you\'re in the air when the potion wears off, you fall unless you have some other means of staying aloft.

This potion\'s clear liquid floats at the top of its container and has cloudy white impurities drifting in it.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Gaseous Form', 'Potion', NULL, 'Rare', 0, NULL, 'When you drink this potion, you gain the effect of the _Gaseous Form_ spell for 1 hour (no Concentration required) or until you end the effect as a Bonus Action.

This potion\'s container seems to hold fog that moves and pours like water.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Giant Strength', 'Potion', NULL, 'Rarity Varies', 0, NULL, 'When you drink this potion, your Strength score changes for 1 hour. The type of giant determines the score (see the table below). The potion has no effect on you if your Strength is equal to or greater than that score.

This potion\'s transparent liquid has floating in it a sliver of light resembling a giant\'s fingernail.

<table>
  <thead>
    <tr>
      <th>Potion</th>
      <th>Str.</th>
      <th>Rarity</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>Potion of Giant Strength (hill)</td>
      <td>21</td>
      <td>Uncommon</td>
    </tr>
    <tr>
      <td>Potion of Giant Strength (frost or stone)</td>
      <td>23</td>
      <td>Rare</td>
    </tr>
    <tr>
      <td>Potion of Giant Strength (fire)</td>
      <td>25</td>
      <td>Rare</td>
    </tr>
    <tr>
      <td>Potion of Giant Strength (cloud)</td>
      <td>27</td>
      <td>Very Rare</td>
    </tr>
    <tr>
      <td>Potion of Giant Strength (storm)</td>
      <td>29</td>
      <td>Legendary</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Growth', 'Potion', NULL, 'Uncommon', 0, NULL, 'When you drink this potion, you gain the "enlarge" effect of the _Enlarge/Reduce_ spell for 10 minutes (no Concentration required).

The red in the potion\'s liquid continuously expands from a tiny bead to color the clear liquid around it and then contracts. Shaking the bottle fails to interrupt this process.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potions of Healing', 'Potion', NULL, 'Rarity Varies', 0, NULL, 'You regain Hit Points when you drink this potion. The number of Hit Points depends on the potion\'s rarity, as shown in the table below.

Whatever its potency, the potion\'s red liquid glimmers when agitated.

<table>
  <thead>
    <tr>
      <th>Potion</th>
      <th>HP Regained</th>
      <th>Rarity</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>Potion of Healing</td>
      <td>2d4 + 2</td>
      <td>Common</td>
    </tr>
    <tr>
      <td>Potion of Healing (greater)</td>
      <td>4d4 + 4</td>
      <td>Uncommon</td>
    </tr>
    <tr>
      <td>Potion of Healing (superior)</td>
      <td>8d4 + 8</td>
      <td>Rare</td>
    </tr>
    <tr>
      <td>Potion of Healing (supreme)</td>
      <td>10d4 + 20</td>
      <td>Very Rare</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Heroism', 'Potion', NULL, 'Rare', 0, NULL, 'When you drink this potion, you gain 10 Temporary Hit Points that last for 1 hour. For the same duration, you are under the effect of the _Bless_ spell (no Concentration required).

This potion\'s blue liquid bubbles and steams as if boiling.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Invisibility', 'Potion', NULL, 'Rare', 0, NULL, 'This potion\'s container looks empty but feels as though it holds liquid. When you drink the potion, you have the Invisible condition for 1 hour. The effect ends early if you make an attack roll, deal damage, or cast a spell.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Invulnerability', 'Potion', NULL, 'Rare', 0, NULL, 'For 1 minute after you drink this potion, you have Resistance to all damage.

This potion\'s syrupy liquid looks like liquefied iron.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Longevity', 'Potion', NULL, 'Very Rare', 0, NULL, 'When you drink this potion, your physical age is reduced by 1d6 + 6 years, to a minimum of 13 years. Each time you subsequently drink a _Potion of Longevity_, there is 10 percent cumulative chance that you instead age by 1d6 + 6 years.

Suspended in this amber liquid is a tiny heart that, against all reason, is still beating. These ingredients vanish when the potion is opened.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Mind Reading', 'Potion', NULL, 'Rare', 0, NULL, 'When you drink this potion, you gain the effect of the _Detect Thoughts_ spell (save DC 13) for 10 minutes (no Concentration required).

This potion\'s dense, purple liquid has an ovoid cloud of pink floating in it.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Poison', 'Potion', NULL, 'Uncommon', 0, NULL, 'This concoction looks, smells, and tastes like a _Potion of Healing_ or another beneficial potion. However, it is actually poison masked by illusion magic. _Identify_ reveals its true nature.

If you drink this potion, you take 4d6 Poison damage and must succeed on a DC 13 Constitution saving throw or have the Poisoned condition for 1 hour.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Resistance', 'Potion', NULL, 'Uncommon', 0, NULL, 'When you drink this potion, you have Resistance to one type of damage for 1 hour. The GM chooses the type or determines it randomly by rolling on the following table.

<table>
  <thead>
    <tr>
      <th>1d10</th>
      <th>Damage Type</th>
      <th>1d10</th>
      <th>Damage Type</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>1</td>
      <td>Acid</td>
      <td>6</td>
      <td>Necrotic</td>
    </tr>
    <tr>
      <td>2</td>
      <td>Cold</td>
      <td>7</td>
      <td>Poison</td>
    </tr>
    <tr>
      <td>3</td>
      <td>Fire</td>
      <td>8</td>
      <td>Psychic</td>
    </tr>
    <tr>
      <td>4</td>
      <td>Force</td>
      <td>9</td>
      <td>Radiant</td>
    </tr>
    <tr>
      <td>5</td>
      <td>Lightning</td>
      <td>10</td>
      <td>Thunder</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Speed', 'Potion', NULL, 'Very Rare', 0, NULL, 'When you drink this potion, you gain the effect of the _Haste_ spell for 1 minute (no Concentration required) without suffering the wave of lethargy that typically occurs when the effect ends.

This potion\'s yellow fluid is streaked with black and swirls on its own.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Vitality', 'Potion', NULL, 'Very Rare', 0, NULL, 'When you drink this potion, it removes any Exhaustion levels you have and ends the Poisoned condition on you. For the next 24 hours, you regain the maximum number of Hit Points for any Hit Point Die you spend.

This potion\'s crimson liquid regularly pulses with dull light, calling to mind a heartbeat.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Potion of Water Breathing', 'Potion', NULL, 'Uncommon', 0, NULL, 'You can breathe underwater for 24 hours after drinking this potion.
This potion\'s cloudy green fluid smells of the sea and has a jellyfish-like bubble floating in it.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Quarterstaff of the Acrobat', 'Weapon', 'Quarterstaff', 'Very Rare (Requires Attunement)', 1, NULL, 'You have a +2 bonus to attack rolls and damage rolls made with this magic weapon.

While holding this weapon, you can cause it to emit green Dim Light out to 10 feet, either as a Bonus Action or after you roll Initiative, or you can extinguish the light as a Bonus Action.

While holding this weapon, you can take a Bonus Action to alter its form, turning it into a 6-inch rod (for ease of storage) or a 10-foot pole, or reverting it a Quarterstaff; the weapon will elongate only as far as the surrounding space allows.

In certain forms, the weapon has the following additional properties.

_Acrobatic Assist (Quarterstaff and 10-Foot Pole Forms Only)._ While holding this weapon, you have Advantage on Dexterity (Acrobatics) checks.

_Attack Deflection (Quarterstaff Form Only)._ When you are hit by an attack while holding the weapon, you can take a Reaction to twirl the weapon around you, gaining a +5 bonus to your Armor Class against the triggering attack, potentially causing the attack to miss you. You can\'t use this property again until you finish a Short or Long Rest.

_Ranged Weapon (Quarterstaff Form Only)._ This weapon has the Thrown property with a normal range of 30 feet and a long range of 120 feet. Immediately after you make a ranged attack with the weapon, it flies back to your hand.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Animal Influence', 'Ring', NULL, 'Rare', 0, NULL, 'This ring has 3 charges, and it regains 1d3 expended charges daily at dawn. While wearing the ring, you can expend 1 charge to cast one of the following spells (save DC 13) from it:

- _Animal Friendship_
- _Fear_ (affects Beasts only)
- _Speak with Animals_');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Djinni Summoning', 'Ring', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'While wearing this ring, you can take a Magic action to summon a particular **Djinni** from the Elemental Plane of Air. The djinni appears in an unoccupied space you choose within 120 feet of yourself. It remains as long as you maintain Concentration, to a maximum of 1 hour, or until it drops to 0 Hit Points.

While summoned, the djinni is Friendly to you and your allies, and it obeys your commands. If you fail to command it, the djinni defends itself against attackers but takes no other actions.

After the djinni departs, it can\'t be summoned again for 24 hours, and the ring becomes nonmagical if the djinni dies.

_Rings of Djinni Summoning_ are often created by the djinn they summon and given to mortals as gifts of friendship or tokens of esteem.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Elemental Command', 'Ring', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'Each _Ring of Elemental Command_ is linked to one of the four Elemental Planes. The GM chooses or randomly determines the linked plane. For example, a _Ring of Elemental Command_ (air) is linked to the Elemental Plane of Air.

Every _Ring of Elemental Command_ has the following two properties:

**Elemental Bane.** While wearing the ring, you have Advantage on attack rolls against Elementals and they have Disadvantage on attack rolls against you.

**Elemental Compulsion.** While wearing the ring, you can take a Magic action to try to compel an Elemental you see within 60 feet of yourself. The Elemental makes a DC 18 Wisdom saving throw. On a failed save, the Elemental has the Charmed condition until the start your next turn, and you determine what it does with its move and action on its next turn.

_Elemental Focus._ While wearing the ring, you benefit from additional properties corresponding to the ring\'s linked Elemental Plane:

**Air.** You know Auran, you have Resistance to Lightning damage, and you have a Fly Speed equal to your Speed and can hover.

**Earth.** You know Terran, and you have Resistance to Acid damage. Terrain composed of rubble, rocks, or dirt isn\'t Difficult Terrain for you. In addition, you can move through solid earth or rock as if those areas were Difficult Terrain without disturbing the matter through which you pass. If you end your turn in solid earth or rock, you are shunted out to the nearest unoccupied space you last occupied.

**Fire.** You know Ignan, and you have Immunity to Fire damage.

**Water.** You know Aquan, you gain a Swim Speed of 60 feet, and you can breathe underwater.

_Spellcasting._ The ring has 5 charges and regains 1d4 + 1 expended charges daily at dawn. While wearing the ring, you can cast a spell from it. Choose the spell from the list of available spells based on the Elemental Plane the ring is linked to, as shown in the following table. The table indicates how many charges you must expend to cast the spell, which has a save DC of 18.

<table>
  <thead>
    <tr>
      <th>Plane</th>
      <th>Spells (Charges)</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>Air</td>
      <td>*Chain Lightning* (3 charges), *Feather Fall* (0 charges), *Gust of Wind* (2 charges), *Wind Wall* (1 charge)</td>
    </tr>
    <tr>
      <td>Earth</td>
      <td>*Earthquake* (5 charges), *Stone Shape* (2 charges), *Stoneskin* (3 charges), *Wall of Stone* (3 charges)</td>
    </tr>
    <tr>
      <td>Fire</td>
      <td>*Burning Hands* (1 charge), *Fireball* (2 charges), *Fire Storm* (4 charges), *Wall of Fire* (3 charges)</td>
    </tr>
    <tr>
      <td>Water</td>
      <td>*Create or Destroy Water* (1 charge), *Ice Storm* (2 charges), *Tsunami* (5 charges), *Wall of Ice* (3 charges), *Water Walk* (2 charges)</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Evasion', 'Ring', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This ring has 3 charges, and it regains 1d3 expended charges daily at dawn. When you fail a Dexterity saving throw while wearing the ring, you can take a Reaction to expend 1 charge to succeed on that save instead.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Feather Falling', 'Ring', NULL, 'Rare (Requires Attunement)', 1, NULL, 'When you fall while wearing this ring, you descend 60 feet per round and take no damage from falling.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Free Action', 'Ring', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While you wear this ring, Difficult Terrain doesn\'t cost you extra movement. In addition, magic can neither reduce any of your Speeds nor cause you to have the Paralyzed or Restrained condition.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Invisibility', 'Ring', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'While wearing this ring, you can take a Magic action to give yourself the Invisible condition. You remain Invisible until the ring is removed or until you take a Bonus Action to become visible again.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Jumping', 'Ring', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While wearing this ring, you can cast _Jump_ from it, but can target only yourself when you do so.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Mind Shielding', 'Ring', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While wearing this ring, you are immune to magic that allows other creatures to read your thoughts, determine whether you are lying, know your alignment, or know your creature type. Creatures can telepathically communicate with you only if you allow it.

You can take a Magic action to cause the ring to become imperceptible until you take another Magic action to make it perceptible, until you remove the ring, or until you die.

If you die while wearing the ring, your soul enters it, unless it already houses a soul. You can remain in the ring or depart for the afterlife. As long as your soul is in the ring, you can telepathically communicate with any creature wearing it. A wearer can\'t prevent this telepathic communication.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Protection', 'Ring', NULL, 'Rare (Requires Attunement)', 1, NULL, 'You gain a +1 bonus to Armor Class and saving throws while wearing this ring.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Regeneration', 'Ring', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'While wearing this ring, you regain 1d6 Hit Points every 10 minutes if you have at least 1 Hit Point. If you lose a body part, the ring causes the missing part to regrow and return to full functionality after 1d6 + 1 days if you have at least 1 Hit Point the whole time.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Resistance', 'Ring', NULL, 'Rare', 0, NULL, 'You have Resistance to one damage type while wearing this ring. The gemstone in the ring indicates the type, which the GM chooses or determines randomly by rolling on the following table.

<table>
  <thead>
    <tr>
      <th>1d10</th>
      <th>Damage Type</th>
      <th>Gemstone</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>1</td>
      <td>Acid</td>
      <td>Pearl</td>
    </tr>
    <tr>
      <td>2</td>
      <td>Cold</td>
      <td>Tourmaline</td>
    </tr>
    <tr>
      <td>3</td>
      <td>Fire</td>
      <td>Garnet</td>
    </tr>
    <tr>
      <td>4</td>
      <td>Force</td>
      <td>Sapphire</td>
    </tr>
    <tr>
      <td>5</td>
      <td>Lightning</td>
      <td>Citrine</td>
    </tr>
    <tr>
      <td>6</td>
      <td>Necrotic</td>
      <td>Jet</td>
    </tr>
    <tr>
      <td>7</td>
      <td>Poison</td>
      <td>Amethyst</td>
    </tr>
    <tr>
      <td>8</td>
      <td>Psychic</td>
      <td>Jade</td>
    </tr>
    <tr>
      <td>9</td>
      <td>Radiant</td>
      <td>Topaz</td>
    </tr>
    <tr>
      <td>10</td>
      <td>Thunder</td>
      <td>Spinel</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Shooting Stars', 'Ring', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'You can cast _Dancing Lights_ or _Light_ from the ring.

The ring has 6 charges and regains 1d6 expended charges daily at dawn. You can expend its charges to use the properties below.

**_Faerie Fire._** You can expend 1 charge to cast _Faerie Fire_ from the ring.

**_Lightning Spheres._** You can expend 2 charges as a Magic action to create up to four 3-foot-diameter spheres of lightning. Each sphere appears in an unoccupied space you can see within 120 feet of yourself. The spheres last as long as you maintain Concentration, up to 1 minute. Each sphere sheds Dim Light in a 30-foot radius.

As a Bonus Action, you can move each sphere up to 30 feet, but no farther than 120 feet away from yourself. The first time the sphere comes within 5 feet of a creature other than you that isn\'t behind Total Cover, the sphere discharges lightning at that creature and disappears. That creature makes a DC 15 Dexterity saving throw. On a failed save, the creature takes Lightning damage based on the number of spheres you created, as shown in the following table. On a successful save, the creature takes half as much damage.

<table>
  <thead>
    <tr>
      <th>Number of Spheres</th>
      <th>Lightning Damage</th>
      <th>Number of Spheres</th>
      <th>Lightning Damage</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>1</td>
      <td>4d12</td>
      <td>3</td>
      <td>2d6</td>
    </tr>
    <tr>
      <td>2</td>
      <td>5d4</td>
      <td>4</td>
      <td>2d4</td>
    </tr>
  </tbody>
</table>

_Shooting Stars._ You can expend 1 to 3 charges as a Magic action. For every charge you expend, you launch a glowing mote of light from the ring at a point you can see within 60 feet of yourself. Each creature in a 15-foot Cube originating from that point is showered in sparks and makes a DC 15 Dexterity saving throw, taking 5d4 Radiant damage on a failed save or half as much damage on a successful one.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Spell Storing', 'Ring', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This ring stores spells cast into it, holding them until the attuned wearer uses them. The ring can store up to 5 levels worth of spells at a time. When found, it contains 1d6 − 1 levels of stored spells chosen by the GM.

Any creature can cast a spell of level 1 through 5 into the ring by touching the ring as the spell is cast. The spell has no effect other than to be stored in the ring. If the ring can\'t hold the spell, the spell is expended without effect. The level of the slot used to cast the spell determines how much space it uses.

While wearing this ring, you can cast any spell stored in it. The spell uses the slot level, spell save DC, spell attack bonus, and spellcasting ability of the original caster but is otherwise treated as if you cast the spell. The spell cast from the ring is no longer stored in it, freeing up space.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Spell Turning', 'Ring', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'While wearing this ring, you have Advantage on saving throws against spells. If you succeed on the save for a spell of level 7 or lower, the spell has no effect on you. If that spell targeted only you and didn\'t create an area of effect, you can take a Reaction to deflect the spell back at the spell\'s caster; the caster must make a saving throw against the spell using their own spell save DC.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Swimming', 'Ring', NULL, 'Uncommon', 0, NULL, 'You have a Swim Speed of 40 feet while wearing this ring.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Telekinesis', 'Ring', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'While wearing this ring, you can cast _Telekinesis_ from it.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of the Ram', 'Ring', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This ring has 3 charges and regains 1d3 expended charges daily at dawn. While wearing the ring, you can take a Magic action to expend 1 to 3 charges to make a ranged spell attack against one creature you can see within 60 feet of yourself. The ring produces a spectral ram\'s head and makes its attack roll with a +7 bonus. On a hit, for each charge you spend, the target takes 2d10 Force damage and is pushed 5 feet away from you.

Alternatively, you can expend 1 to 3 of the ring\'s charges as a Magic action to try to break a nonmagical object you can see within 60 feet of yourself that isn\'t being worn or carried. The ring makes a Strength check with a +5 bonus for each charge you spend.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Three Wishes', 'Ring', NULL, 'Legendary', 0, NULL, 'While wearing this ring, you can expend 1 of its 3 charges to cast _Wish_ from it. The ring becomes nonmagical when you use the last charge.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Warmth', 'Ring', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'If you take Cold damage while wearing this ring, the ring reduces the damage you take by 2d8.

In addition, while wearing this ring, you and everything you wear and carry are unharmed by temperatures of 0 degrees Fahrenheit or lower.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of Water Walking', 'Ring', NULL, 'Uncommon', 0, NULL, 'While wearing this ring, you cast _Water Walk_ from it, targeting only yourself.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Ring of X-ray Vision', 'Ring', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While wearing this ring, you can take a Magic action to gain X-ray vision with a range of 30 feet for 1 minute. To you, solid objects within that radius appear transparent and don\'t prevent light from passing through them. The vision can penetrate 1 foot of stone, 1 inch of common metal, or up to 3 feet of wood or dirt. Thicker substances or a thin sheet of lead block the vision.

Whenever you use the ring again before taking a Long Rest, you must succeed on a DC 15 Constitution saving throw or gain 1 Exhaustion level.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Robe of Eyes', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This robe is adorned with eyelike patterns. While you wear the robe, you gain the following benefits:

**All-Around Vision.** The robe gives you Advantage on Wisdom (Perception) checks that rely on sight.

**Special Senses.** You have Darkvision and Truesight, both with a range of 120 feet.

_Drawbacks._ A _Light_ spell cast on the robe or a _Daylight_ spell cast within 5 feet of the robe gives you the Blinded condition for 1 minute. At the end of each of your turns, you make a Constitution saving throw (DC 11 for _Light_ or DC 15 for _Daylight_), ending the condition on yourself on a success.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Robe of Scintillating Colors', 'Wondrous Item', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'This robe has 3 charges, and it regains 1d3 expended charges daily at dawn. While you wear it, you can take a Magic action and expend 1 charge to cause the garment to display a shifting pattern of dazzling hues until the end of your next turn. During this time, the robe sheds Bright Light in a 30-foot radius and Dim Light for an additional 30 feet, and creatures that can see you have Disadvantage on attack rolls against you. Any creature in the Bright Light that can see you when the robe\'s power is activated must succeed on a DC 15 Wisdom saving throw or have the Stunned condition until the effect ends.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Robe of Stars', 'Wondrous Item', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'This black or dark-blue robe is embroidered with small white or silver stars. You gain a +1 bonus to saving throws while you wear it.

Six stars, located on the robe\'s upper-front portion, are particularly large. While wearing this robe, you can take a Magic action to remove one of the stars and expend it to cast the level 5 version of _Magic Missile_. Daily at dusk, 1d6 removed stars reappear on the robe.

While you wear the robe, you can take a Magic action to enter the Astral Plane along with everything you are wearing and carrying. You remain there until you take a Magic action to return to the plane you were on. You reappear in the last space you occupied or, if that space is occupied, the nearest unoccupied space.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Robe of the Archmagi', 'Wondrous Item', NULL, 'Legendary (Requires Attunement by a Sorcerer, Warlock, or Wizard)', 1, 'by a Sorcerer, Warlock, or Wizard', 'This elegant garment is made from exquisite cloth and adorned with runes.

You gain these benefits while wearing the robe.

_Armor._ If you aren\'t wearing armor, your base Armor Class is 15 plus your Dexterity modifier.

_Magic Resistance._ You have Advantage on saving throws against spells and other magical effects.

_War Mage._ Your spell save DC and spell attack bonus each increase by 2.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Robe of Useful Items', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, 'This robe has cloth patches of various shapes and colors covering it. While wearing the robe, you can take a Magic action to detach one of the patches, causing it to become the object or creature it represents. Once the last patch is removed, the robe becomes an ordinary garment.

The robe has two of each of the following patches:

- Bullseye Lantern (filled and lit)
- Dagger
- Mirror
- Pole
- Rope (coiled)
- Sack

In addition, the robe has 4d4 other patches. The GM chooses the patches or determines them randomly by rolling on the following table.

<table>
  <thead>
    <tr>
      <th>1d100</th>
      <th>Patch</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>01–08</td>
      <td>Bag of 100 GP</td>
    </tr>
    <tr>
      <td>09–15</td>
      <td>Silver coffer (1 foot long, 6 inches wide and deep) worth 500 GP</td>
    </tr>
    <tr>
      <td>16–22</td>
      <td>Iron door (up to 10 feet wide and 10 feet high, barred on one side of your choice), which you can place in an opening you can reach; it conforms to fit the opening, attaching and hinging itself</td>
    </tr>
    <tr>
      <td>23–30</td>
      <td>10 gems worth 100 GP each</td>
    </tr>
    <tr>
      <td>31–44</td>
      <td>Wooden ladder (24 feet long)</td>
    </tr>
    <tr>
      <td>45–51</td>
      <td>Riding Horse with a Riding Saddle</td>
    </tr>
    <tr>
      <td>52–59</td>
      <td>Open pit (a 10-foot Cube), which you can place on the ground within 10 feet of yourself</td>
    </tr>
    <tr>
      <td>60–68</td>
      <td>4 Potions of Healing</td>
    </tr>
    <tr>
      <td>69–75</td>
      <td>Rowboat (12 feet long)</td>
    </tr>
    <tr>
      <td>76–83</td>
      <td>Spell Scroll containing one spell of level 1, 2, or 3 (your choice)</td>
    </tr>
    <tr>
      <td>84–90</td>
      <td>2 Mastiffs</td>
    </tr>
    <tr>
      <td>91–96</td>
      <td>Window (2 feet by 4 feet, up to 2 feet deep), which you can place on a vertical surface you can reach</td>
    </tr>
    <tr>
      <td>97–00</td>
      <td>Portable Ram</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Rod of Absorption', 'Rod', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'While holding this rod, you can take a Reaction to absorb a spell that is targeting only you and doesn\'t create an area of effect. The absorbed spell\'s effect is canceled, and the spell\'s energy—not the spell itself—is stored in the rod. The energy has the same level as the spell when it was cast. A canceled spell dissipates with no effect, and any resources used to cast it are wasted. The rod can absorb and store up to 50 levels of energy over the course of its existence. Once the rod absorbs 50 levels of energy, it can\'t absorb more. If you are targeted by a spell that the rod can\'t store, the rod has no effect on that spell.

When you become attuned to the rod, you know how many levels of energy the rod has absorbed over the course of its existence and how many levels of spell energy it currently has stored.

If you are a spellcaster holding the rod, you can convert energy stored in it into spell slots to cast spells you have prepared or know. You can create spell slots only of a level equal to or lower than your own spell slots, up to a maximum of level 5. You use the stored levels in place of your slots but otherwise cast the spell as normal. For example, you can use 3 levels stored in the rod as a level 3 spell slot.

A newly found rod typically has 1d10 levels of spell energy stored in it. A rod that can no longer absorb spell energy and has no energy remaining becomes nonmagical.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Rod of Alertness', 'Rod', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'This rod has the following properties.

_Alertness._ While holding the rod, you have Advantage on Wisdom (Perception) checks and on Initiative rolls.

_Spells._ While holding the rod, you can cast the following spells from it:

- _Detect Evil and Good_
- _Detect Magic_
- _Detect Poison and Disease_
- _See Invisibility_

_Protective Aura._ As a Magic action, you can plant the haft end of the rod in the ground, whereupon the rod\'s head sheds Bright Light in a 60-foot radius and Dim Light for an additional 60 feet. While in that Bright Light, you and your allies gain a +1 bonus to Armor Class and saving throws and can sense the location of any Invisible creature that is also in the Bright Light.

The rod\'s head stops glowing and the effect ends after 10 minutes or when a creature takes a Magic action to pull the rod from the ground. Once used, this property can\'t be used again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Rod of Lordly Might', 'Rod', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'This rod has a flanged head, and it functions as a magic Mace that grants a +3 bonus to attack rolls and damage rolls made with it. The rod has properties associated with six different buttons that are set in a row along the haft. It has three other properties as well, detailed below.

_Buttons._ You can press one of the following buttons as a Bonus Action; a button\'s effect lasts until you push a different button or until you push the same button again, which causes the rod to revert to its normal form:

**Button 1.** A fiery blade sprouts from the end opposite the rod\'s flanged head. The flames shed Bright Light in a 40-foot radius and Dim Light for an additional 40 feet, and the blade functions as a magic Longsword or Shortsword (your choice) that deals an extra 2d6 Fire damage on a hit.

**Button 2.** The rod\'s flanged head folds down and two crescent-shaped blades spring out, transforming the rod into a magic Battleaxe that grants a +3 bonus to attack rolls and damage rolls made with it.

**Button 3.** The rod\'s flanged head folds down, a spear point springs from the rod\'s tip, and the rod\'s handle lengthens into a 6-foot haft, transforming the rod into a magic Spear that grants a +3 bonus to attack rolls and damage rolls made with it.

**Button 4.** The rod transforms into a climbing pole up to 50 feet long (you specify the length), though the rod\'s buttons remain within your reach. In surfaces as hard as granite, a spike at the bottom and three hooks at the top anchor the pole. Horizontal bars 3 inches long fold out from the sides, 1 foot apart, forming a ladder. The pole can bear up to 4,000 pounds. More weight or lack of solid anchoring causes the rod to revert to its normal form.

**Button 5.** The rod transforms into a handheld battering ram and grants its user a +10 bonus to Strength (Athletics) checks made to break through doors, barricades, and other barriers.

**Button 6.** The rod assumes or remains in its normal form and indicates magnetic north. (Nothing happens if this function of the rod is used in a location that has no magnetic north.) The rod also gives you knowledge of your approximate depth beneath the ground or your height above it.

_Drain Life._ When you hit a creature with a melee attack using the rod, you can force the target to make a DC 17 Constitution saving throw. On a failed save, the target takes an extra 4d6 Necrotic damage, and you regain a number of Hit Points equal to half that Necrotic damage. Once used, this property can\'t be used again until the next dawn.

_Paralyze._ When you hit a creature with a melee attack using the rod, you can force the target to make a DC 17 Constitution saving throw. On a failed save, the target has the Paralyzed condition for 1 minute. The target repeats the save at the end of each of its turns, ending the effect on a success. Once used, this property can\'t be used again until the next dawn.

_Terrify._ While holding the rod, you can take a Magic action to force each creature you can see within 30 feet of yourself to make a DC 17 Wisdom saving throw. On a failed save, a target has the Frightened condition for 1 minute. A Frightened target repeats the save at the end of each of its turns, ending the effect on itself on a success. Once used, this property can\'t be used again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Rod of Resurrection', 'Rod', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'The rod has 5 charges. While you hold it, you can cast one of the following spells from it: _Heal_ (expends 1 charge) or _Resurrection_ (expends 5 charges).

The rod regains 1 expended charge daily at dawn. If you expend the last charge, roll 1d20. On a 1, the rod disappears in a harmless burst of radiance.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Rod of Rulership', 'Rod', NULL, 'Rare (Requires Attunement)', 1, NULL, 'You can take a Magic action to present the rod and command obedience from each creature of your choice that you can see within 120 feet of yourself. Each target must succeed on a DC 15 Wisdom saving throw or have the Charmed condition for 8 hours. While Charmed in this way, the creature regards you as its trusted leader. If harmed by you or your allies or commanded to do something contrary to its nature, a target ceases to be Charmed in this way. Once used, this property can\'t be used again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Rod of Security', 'Rod', NULL, 'Very Rare', 0, NULL, 'While holding this rod, you can take a Magic action to activate it. The rod then instantly transports you and up to 199 other willing creatures you can see to a demiplane. You choose the form the demiplane takes. It could be a tranquil garden, a cheery tavern, an immense palace, a tropical island, a fantastic carnival, or whatever else you can imagine. Regardless of its nature, the demiplane contains enough water and food to sustain its visitors, and the demiplane\'s environment can\'t harm its occupants. Everything else that can be interacted with there can exist only there. For example, a flower picked from a garden there disappears if it is taken outside the demiplane.

For each hour spent in the demiplane, a visitor regains Hit Points as if it had spent 1 Hit Point Die. Also, creatures don\'t age while there, although time passes normally. Visitors can remain there for up to 200 days divided by the number of creatures present (round down).

When the time runs out or you take a Magic action to end the effect, all visitors reappear in the location they occupied when you activated the rod or an unoccupied space nearest that location. Once used, this property can\'t be used again until 10 days have passed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Rope of Climbing', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, 'This 60-foot length of rope can hold up to 3,000 pounds. While holding one end of the rope, you can take a Magic action to command the other end of the rope to animate and move toward a destination you choose, up to the rope\'s length away from you. That end moves 10 feet on your turn when you first command it and 10 feet at the start of each of your subsequent turns until reaching its destination or until you tell it to stop. You can also tell the rope to fasten itself securely to an object or to unfasten itself, to knot or unknot itself, or to coil itself for carrying.

If you tell the rope to knot, large knots appear at 1-foot intervals along the rope. While knotted, the rope shortens to a 50-foot length and grants Advantage on ability checks made to climb using the rope.

The rope has AC 20, HP 20, and Immunity to Poison and Psychic damage. It regains 1 Hit Point every 5 minutes as long as it has at least 1 Hit Point. If the rope drops to 0 Hit Points, it is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Rope of Entanglement', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'This rope is 30 feet long. While holding one end of the rope, you can take a Magic action to command the other end to dart forward and entangle one creature you can see within 20 feet of yourself. The target must succeed on a DC 15 Dexterity saving throw or have the Restrained condition. You can release the target by letting go of your end of the rope (causing the rope to coil up in the target\'s space) or by using a Bonus Action to repeat the command (causing the rope to coil up in your hand).

A target Restrained by the rope can take an action to make its choice of a DC 15 Strength (Athletics) or Dexterity (Acrobatics) check. On a successful check, the target is no longer Restrained by the rope. If you\'re still holding onto the rope when a target escapes from it, you can take a Reaction to command the rope to coil up in your hand; otherwise, the rope coils up in the target\'s space.

The rope has AC 20, HP 20, and Immunity to Poison and Psychic damage. It regains 1 Hit Point every 5 minutes as long as it has at least 1 Hit Point. If the rope drops to 0 Hit Points, it is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Scarab of Protection', 'Wondrous Item', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'This beetle-shaped medallion provides three benefits while it is on your person.

_Defense._ You gain a +1 bonus to Armor Class.

_Preservation._ The scarab has 12 charges. If you fail a saving throw against a Necromancy spell or a harmful effect originating from an Undead, you can take a Reaction to expend 1 charge and turn the failed save into a successful one. The scarab crumbles into powder and is destroyed when its last charge is expended.

_Spell Resistance._ You have Advantage on saving throws against spells.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Scimitar of Speed', 'Weapon', 'Scimitar', 'Very Rare (Requires Attunement)', 1, NULL, 'You gain a +2 bonus to attack rolls and damage rolls made with this magic weapon. In addition, you can make one attack with it as a Bonus Action on each of your turns.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Sending Stones', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, '_Sending Stones_ come in pairs, with each stone carved to match the other so the pairing is easily recognized. While you touch one stone, you can cast _Sending_ from it. The target is the bearer of the other stone. If no creature bears the other stone, you know that fact as soon as you use the stone, and you don\'t cast the spell.

Once _Sending_ is cast using either stone, the stones can\'t be used again until the next dawn. If one of the stones in a pair is destroyed, the other one becomes nonmagical.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Sentinel Shield', 'Armor', 'Shield', 'Uncommon', 0, NULL, 'While holding this Shield, you have Advantage on Initiative rolls and Wisdom (Perception) checks. The Shield is emblazoned with a symbol of an eye.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Shield, +1, +2, or +3', 'Armor', 'Shield', 'Uncommon (+1), Rare (+2), or Very Rare (+3)', 0, NULL, 'While holding this Shield, you have a bonus to Armor Class determined by the Shield\'s rarity, in addition to the Shield\'s normal bonus to AC.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Shield of Missile Attraction', 'Armor', 'Shield', 'Rare (Requires Attunement)', 1, NULL, 'While holding this Shield, you have Resistance to damage from attacks made with Ranged weapons.

_Curse._ This Shield is cursed. Attuning to it curses you until you are targeted by a _Remove Curse_ spell or similar magic. Removing the Shield fails to end the curse on you. Whenever an attack with a Ranged weapon targets a creature within 10 feet of you, the curse causes you to become the target instead.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Shield of the Cavalier', 'Armor', 'Shield', 'Very Rare (Requires Attunement)', 1, NULL, 'While holding this Shield, you have a +2 bonus to Armor Class. This bonus is in addition to the Shield\'s normal bonus to AC.

The Shield has the following additional properties that you can use while holding it.

_Forceful Bash._ When you take the Attack action, you can make one of the attack rolls using the Shield against a target within 5 feet of yourself. Apply your Proficiency Bonus and Strength modifier to the attack roll. On a hit, the Shield deals Force damage to the target equal to 2d6 + 2 plus your Strength modifier, and if the target is a creature, you can push it up to 10 feet directly away from yourself. If the creature is your size or smaller, you can also knock it down, giving it the Prone condition.

_Protective Field._ As a Reaction, when you or an ally you can see within 5 feet of you is targeted by an attack or makes a saving throw against an area of effect, you can use the Shield to create an immobile 5-foot Emanation originating from you. When the Emanation appears, any creatures or objects not fully contained within it are pushed into the nearest unoccupied spaces outside it. The attack or area of effect that triggered the Reaction has no effect on creatures and objects inside the Emanation, which lasts as long as you maintain Concentration, up to 1 minute. Nothing can pass into or out of the Emanation. A creature or object inside the Emanation can\'t be damaged by attacks or effects originating from outside, nor can a creature inside the Emanation damage anything outside it. Once this property is used, it can\'t be used again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Slippers of Spider Climbing', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While you wear these light shoes, you can move up, down, and across vertical surfaces and along ceilings, while leaving your hands free. You have a Climb Speed equal to your Speed. However, the slippers don\'t allow you to move this way on a slippery surface, such as one covered by ice or oil.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Sovereign Glue', 'Wondrous Item', NULL, 'Legendary', 0, NULL, 'This viscous, milky-white substance can form a permanent adhesive bond between any two objects. It must be stored in a jar or flask that has been coated inside with _Oil of Slipperiness_. When found, a container contains 1d6 + 1 ounces.

One ounce of the glue can cover a 1-foot square surface. Applying an ounce of _Sovereign Glue_ takes a Utilize action, and the applied glue takes 1 minute to set. Once it has done so, the bond it creates can be broken only by the application of _Universal Solvent_ or _Oil of Etherealness_, or with a _Wish_ spell.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Spellguard Shield', 'Armor', 'Shield', 'Very Rare (Requires Attunement)', 1, NULL, 'While holding this Shield, you have Advantage on saving throws against spells and other magical effects, and spell attack rolls have Disadvantage against you.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Spell Scroll', 'Scroll', NULL, 'Rarity Varies', 0, NULL, 'A _Spell Scroll_ bears the words of a single spell, written in a mystical cipher. If the spell is on your spell list, you can read the scroll and cast its spell without Material components. Otherwise, the scroll is unintelligible. Casting the spell by reading the scroll requires the spell\'s normal casting time. Once the spell is cast, the scroll crumbles to dust. If the casting is interrupted, the scroll isn\'t lost.

If the spell is on your spell list but of a higher level than you can normally cast, you make an ability check using your spellcasting ability to determine whether you cast the spell. The DC equals 10 plus the spell\'s level. On a failed check, the spell disappears from the scroll with no other effect.

The level of the spell on the scroll determines the spell\'s saving throw DC and attack bonus, as well as the scroll\'s rarity, as shown in the following table.

<table>
  <thead>
    <tr>
      <th>Spell Level</th>
      <th>Rarity</th>
      <th>Save DC</th>
      <th>Attack Bonus</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>Cantrip</td>
      <td>Common</td>
      <td>13</td>
      <td>+5</td>
    </tr>
    <tr>
      <td>1</td>
      <td>Common</td>
      <td>13</td>
      <td>+5</td>
    </tr>
    <tr>
      <td>2</td>
      <td>Uncommon</td>
      <td>13</td>
      <td>+5</td>
    </tr>
    <tr>
      <td>3</td>
      <td>Uncommon</td>
      <td>15</td>
      <td>+7</td>
    </tr>
    <tr>
      <td>4</td>
      <td>Rare</td>
      <td>15</td>
      <td>+7</td>
    </tr>
    <tr>
      <td>5</td>
      <td>Rare</td>
      <td>17</td>
      <td>+9</td>
    </tr>
    <tr>
      <td>6</td>
      <td>Very Rare</td>
      <td>17</td>
      <td>+9</td>
    </tr>
    <tr>
      <td>7</td>
      <td>Very Rare</td>
      <td>18</td>
      <td>+10</td>
    </tr>
    <tr>
      <td>8</td>
      <td>Very Rare</td>
      <td>18</td>
      <td>+10</td>
    </tr>
    <tr>
      <td>9</td>
      <td>Legendary</td>
      <td>19</td>
      <td>+11</td>
    </tr>
  </tbody>
</table>

_Copying a Scroll into a Spellbook._ A Wizard spell on a _Spell Scroll_ can be copied into a spellbook. When a spell is copied in this way, the copier must succeed on an Intelligence (Arcana) check with a DC equal to 10 plus the spell\'s level. On a successful check, the spell is copied. Whether the check succeeds or fails, the _Spell Scroll_ is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Sphere of Annihilation', 'Wondrous Item', NULL, 'Legendary', 0, NULL, 'This 2-foot-diameter black sphere is a hole in the multiverse, hovering in space and stabilized by a magical field surrounding it.

The sphere obliterates all matter it passes through and all matter that passes through it. Artifacts are the exception. Unless an Artifact is susceptible to damage from a _Sphere of Annihilation_, it passes through the sphere unscathed. Anything else that touches the sphere but isn\'t wholly engulfed and obliterated by it takes 8d10 Force damage.

_Controlling the Sphere._ A _Sphere of Annihilation_ is stationary until someone takes control of it. If you are within 60 feet of a sphere, you can take a Magic action to make a DC 25 Intelligence (Arcana) check. On a successful check, you control the sphere until the start of your next turn, and if it was under another creature\'s control, that creature loses control of the sphere. On a failed check, the sphere moves 10 feet toward you in a straight line.

While in control of the sphere, you can take a Bonus Action to cause it to move in one direction of your choice, up to a number of feet equal to 5 times your Intelligence modifier (minimum 5 feet). Any creature whose space the sphere enters must succeed on a DC 19 Dexterity saving throw or be touched by it, taking 8d10 Force damage. A creature reduced to 0 Hit Points by this damage is obliterated, leaving its possessions behind but no other physical remains.

_Sphere Interactions._ If the sphere comes into contact with a planar portal (such as that created by the _Gate_ spell) or an extradimensional space (such as that within a _Portable Hole_), the GM determines randomly what happens using the following table.

<table>
  <thead>
    <tr>
      <th>1d100</th>
      <th>Result</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>01–50</td>
      <td>The sphere is destroyed.</td>
    </tr>
    <tr>
      <td>51–85</td>
      <td>The sphere moves through the portal or into the extradimensional space.</td>
    </tr>
    <tr>
      <td>86–00</td>
      <td>A spatial rift sends the sphere and each creature and object within 180 feet of the sphere to a random plane of existence.</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Charming', 'Staff', NULL, 'Rare (Requires Attunement by a Bard, Cleric, Druid, Sorcerer, Warlock, or Wizard)', 1, 'by a Bard, Cleric, Druid, Sorcerer, Warlock, or Wizard', 'This staff has 10 charges. While holding the staff, you can use any of its properties:

**Cast Spell.** You can expend 1 of the staff\'s charges to cast _Charm Person_, _Command_, or _Comprehend Languages_ from it using your spell save DC.

**Reflect Enchantment.** If you succeed on a saving throw against an Enchantment spell that targets only you, you can take a Reaction to expend 1 charge from the staff and turn the spell back on its caster as if you had cast the spell.

**Resist Enchantment.** If you fail a saving throw against an Enchantment spell that targets only you, you can turn your failed save into a successful one. You can\'t use this property of the staff again until the next dawn.

_Regaining Charges._ The staff regains 1d8 + 2 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff crumbles to dust and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Fire', 'Staff', NULL, 'Very Rare (Requires Attunement by a Druid, Sorcerer, Warlock, or Wizard)', 1, 'by a Druid, Sorcerer, Warlock, or Wizard', 'You have Resistance to Fire damage while you hold this staff.

_Spells._ The staff has 10 charges. While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Burning Hands*</td>
      <td>1</td>
      <td>*Wall of Fire*</td>
      <td>4</td>
    </tr>
    <tr>
      <td>*Fireball*</td>
      <td>3</td>
      <td></td>
      <td></td>
    </tr>
  </tbody>
</table>

_Regaining Charges._ The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff crumbles into cinders and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Frost', 'Staff', NULL, 'Very Rare (Requires Attunement by a Druid, Sorcerer, Warlock, or Wizard)', 1, 'by a Druid, Sorcerer, Warlock, or Wizard', 'You have Resistance to Cold damage while you hold this staff.

_Spells._ The staff has 10 charges. While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Cone of Cold*</td>
      <td>5</td>
      <td>*Ice Storm*</td>
      <td>4</td>
    </tr>
    <tr>
      <td>*Fog Cloud*</td>
      <td>1</td>
      <td>*Wall of Ice*</td>
      <td>4</td>
    </tr>
  </tbody>
</table>

_Regaining Charges._ The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff turns to water and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Healing', 'Staff', NULL, 'Rare (Requires Attunement by a Bard, Cleric, or Druid)', 1, 'by a Bard, Cleric, or Druid', 'This staff has 10 charges. While holding the staff, you can cast one of the spells on the following table from it, using your spellcasting ability modifier. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Cure Wounds*</td>
      <td>1 charge per spell level (maximum 4 for a level 4 spell)</td>
    </tr>
    <tr>
      <td>*Lesser Restoration*</td>
      <td>2</td>
    </tr>
    <tr>
      <td>*Mass Cure Wounds*</td>
      <td>5</td>
    </tr>
  </tbody>
</table>

_Regaining Charges._ The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff vanishes in a flash of light, lost forever.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Power', 'Staff', NULL, 'Very Rare (Requires Attunement by a Sorcerer, Warlock, or Wizard)', 1, 'by a Sorcerer, Warlock, or Wizard', 'This staff has 20 charges and can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. While holding it, you gain a +2 bonus to Armor Class, saving throws, and spell attack rolls.

_Spells._ While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Cone of Cold*</td>
      <td>5</td>
    </tr>
    <tr>
      <td>*Fireball* (level 5 version)</td>
      <td>5</td>
    </tr>
    <tr>
      <td>*Globe of Invulnerability*</td>
      <td>6</td>
    </tr>
    <tr>
      <td>*Hold Monster*</td>
      <td>5</td>
    </tr>
    <tr>
      <td>*Levitate*</td>
      <td>2</td>
    </tr>
    <tr>
      <td>*Lightning Bolt* (level 5 version)</td>
      <td>5</td>
    </tr>
    <tr>
      <td>*Magic Missile*</td>
      <td>1</td>
    </tr>
    <tr>
      <td>*Ray of Enfeeblement*</td>
      <td>1</td>
    </tr>
    <tr>
      <td>*Wall of Force*</td>
      <td>5</td>
    </tr>
  </tbody>
</table>

_Regaining Charges._ The staff regains 2d8 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff retains its +2 bonus to attack rolls and damage rolls but loses all other properties. On a 20, the staff regains 1d8 + 2 charges.

_Retributive Strike._ You can take a Magic action to break the staff over your knee or against a solid surface. The staff is destroyed and releases its magic in an explosion that fills a 30-foot Emanation originating from itself. You have a 50 percent chance to instantly travel to a random plane of existence, avoiding the explosion. If you fail to avoid the effect, you take Force damage equal to 16 times the number of charges in the staff. Each other creature in the area makes a DC 17 Dexterity saving throw. On a failed save, a creature takes Force damage equal to 4 times the number of charges in the staff. On a successful save, a creature takes half as much damage.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Striking', 'Staff', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'This staff can be wielded as a magic Quarterstaff that grants a +3 bonus to attack rolls and damage rolls made with it.

The staff has 10 charges. When you hit with a melee attack using it, you can expend up to 3 charges. For each charge you expend, the target takes an extra 1d6 Force damage.

_Regaining Charges._ The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff becomes a nonmagical Quarterstaff.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Swarming Insects', 'Staff', NULL, 'Rare (Requires Attunement by a Bard, Cleric, Druid, Sorcerer, Warlock, or Wizard)', 1, 'by a Bard, Cleric, Druid, Sorcerer, Warlock, or Wizard', 'This staff has 10 charges.

_Insect Cloud._ While holding the staff, you can take a Magic action and expend 1 charge to cause a swarm of harmless flying insects to fill a 30-foot Emanation originating from you. The insects remain for 10 minutes, making the area Heavily Obscured for creatures other than you. A strong wind (like that created by _Gust of Wind_) disperses the swarm and ends the effect.

_Spells._ While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC and spell attack modifier. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Giant Insect*</td>
      <td>4</td>
    </tr>
    <tr>
      <td>*Insect Plague*</td>
      <td>5</td>
    </tr>
  </tbody>
</table>

_Regaining Charges._ The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, a swarm of insects consumes and destroys the staff, then disperses.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of the Magi', 'Staff', NULL, 'Legendary (Requires Attunement by a Sorcerer, Warlock, or Wizard)', 1, 'by a Sorcerer, Warlock, or Wizard', 'This staff has 50 charges and can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. While you hold it, you gain a +2 bonus to spell attack rolls.

_Spell Absorption._ While holding the staff, you have Advantage on saving throws against spells. In addition, you can take a Reaction when another creature casts a spell that targets only you. If you do, the staff absorbs the magic of the spell, canceling its effect and gaining a number of charges equal to the absorbed spell\'s level. However, if doing so brings the staff\'s total number of charges above 50, the staff explodes as if you activated its Retributive Strike (see below).

_Spells._ While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Arcane Lock*</td>
      <td>0</td>
    </tr>
    <tr>
      <td>*Conjure Elemental*</td>
      <td>7</td>
    </tr>
    <tr>
      <td>*Detect Magic*</td>
      <td>0</td>
    </tr>
    <tr>
      <td>*Dispel Magic*</td>
      <td>3</td>
    </tr>
    <tr>
      <td>*Enlarge/Reduce*</td>
      <td>0</td>
    </tr>
    <tr>
      <td>*Fireball* (level 7 version)</td>
      <td>7</td>
    </tr>
    <tr>
      <td>*Flaming Sphere*</td>
      <td>2</td>
    </tr>
    <tr>
      <td>*Ice Storm*</td>
      <td>4</td>
    </tr>
    <tr>
      <td>*Invisibility*</td>
      <td>2</td>
    </tr>
    <tr>
      <td>*Knock*</td>
      <td>2</td>
    </tr>
    <tr>
      <td>*Light*</td>
      <td>0</td>
    </tr>
    <tr>
      <td>*Lightning Bolt* (level 7 version)</td>
      <td>7</td>
    </tr>
    <tr>
      <td>*Passwall*</td>
      <td>5</td>
    </tr>
    <tr>
      <td>*Plane Shift*</td>
      <td>7</td>
    </tr>
    <tr>
      <td>*Protection from Evil and Good*</td>
      <td>0</td>
    </tr>
    <tr>
      <td>*Telekinesis*</td>
      <td>5</td>
    </tr>
    <tr>
      <td>*Wall of Fire*</td>
      <td>4</td>
    </tr>
    <tr>
      <td>*Web*</td>
      <td>2</td>
    </tr>
  </tbody>
</table>

_Regaining Charges._ The staff regains 4d6 + 2 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 20, the staff regains 1d12 + 1 charges.

_Retributive Strike._ You can take a Magic action to break the staff over your knee or against a solid surface. The staff is destroyed and releases its magic in an explosion that fills a 30-foot Emanation originating from itself. You have a 50 percent chance to instantly travel to a random plane of existence, avoiding the explosion. If you fail to avoid the effect, you take Force damage equal to 16 times the number of charges in the staff. Each other creature in the area makes a DC 17 Dexterity saving throw. On a failed save, a creature takes Force damage equal to 6 times the number of charges in the staff. On a successful save, a creature takes half as much damage.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of the Python', 'Staff', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'As a Magic action, you can throw this staff so that it lands in an unoccupied space within 10 feet of you, causing the staff to become a **Giant Constrictor Snake** in that space. The snake is under your control and shares your Initiative count, taking its turn immediately after yours.

On your turn, you can mentally command the snake (no action required) if it is within 60 feet of you and you don\'t have the Incapacitated condition. You decide what action the snake takes and where it moves during its turn, or you can issue it a general command, such as to attack your enemies or guard a location. Absent commands from you, the snake defends itself.

As a Bonus Action, you can command the snake to revert to staff form in its current space, and you can\'t use the staff\'s property again for 1 hour. If the snake is reduced to 0 Hit Points, it dies and reverts to its staff form; the staff then shatters and is destroyed. If the snake reverts to staff form before losing all its Hit Points, it regains all of them.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of the Woodlands', 'Staff', NULL, 'Rare (Requires Attunement by a Druid)', 1, 'by a Druid', 'This staff has 6 charges and can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. While holding it, you have a +2 bonus to spell attack rolls.

_Spells._ While holding the staff, you can cast one of the spells on the following table from it, using your spell save DC. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Animal Friendship*</td>
      <td>1</td>
    </tr>
    <tr>
      <td>*Awaken*</td>
      <td>5</td>
    </tr>
    <tr>
      <td>*Barkskin*</td>
      <td>2</td>
    </tr>
    <tr>
      <td>*Locate Animals or Plants*</td>
      <td>2</td>
    </tr>
    <tr>
      <td>*Pass without Trace*</td>
      <td>2</td>
    </tr>
    <tr>
      <td>*Speak with Animals*</td>
      <td>1</td>
    </tr>
    <tr>
      <td>*Speak with Plants*</td>
      <td>3</td>
    </tr>
    <tr>
      <td>*Wall of Thorns*</td>
      <td>6</td>
    </tr>
  </tbody>
</table>

_Tree Form._ You can take a Magic action to plant one end of the staff in earth in an unoccupied space and expend 1 charge to transform the staff into a healthy tree. The tree is 60 feet tall and has a 5-foot-diameter trunk, and its branches at the top spread out in a 20-foot radius. The tree appears ordinary but radiates a faint aura of Transmutation magic that can be discerned with the _Detect Magic_ spell. While touching the tree and using a Magic action, you return the staff to its normal form. Any creature in the tree falls when the tree reverts to a staff.

_Regaining Charges._ The staff regains 1d6 expended charges daily at dawn. If you expend the last charge, roll 1d20. On a 1, the staff loses its properties and becomes a nonmagical Quarterstaff.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Thunder and Lightning', 'Staff', NULL, 'Very Rare (Requires Attunement)', 1, NULL, 'This staff can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. It also has the following additional properties. Once one of these properties is used, it can\'t be used again until the next dawn.

_Lightning._ When you hit with a melee attack using the staff, you can cause the target to take an extra 2d6 Lightning damage (no action required).

_Thunder._ When you hit with a melee attack using the staff, you can cause the staff to emit a crack of thunder audible out to 300 feet (no action required). The target you hit must succeed on a DC 17 Constitution saving throw or have the Stunned condition until the end of your next turn.

**_Thunder and Lightning._** Immediately after you hit with a melee attack using the staff, you can take a Bonus Action to use the Lightning and Thunder properties (see above) at the same time. Doing so doesn\'t expend the daily use of those properties, only the use of this one.

_Lightning Strike._ You can take a Magic action to cause a bolt of lightning to leap from the staff\'s tip in a Line that is 5 feet wide and 120 feet long. Each creature in that Line makes a DC 17 Dexterity saving throw, taking 9d6 Lightning damage on a failed save or half as much damage on a successful one.

_Thunderclap._ You can take a Magic action to cause the staff to produce a thunderclap audible out to 600 feet. Every creature within a 60-foot Emanation originating from you makes a DC 17 Constitution saving throw. On a failed save, a creature takes 2d6 Thunder damage and has the Deafened condition for 1 minute. On a successful save, a creature takes half as much damage only.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Staff of Withering', 'Staff', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This staff has 3 charges and regains 1d3 expended charges daily at dawn.

The staff can be wielded as a magic Quarterstaff. On a hit, it deals damage as a normal Quarterstaff, and you can expend 1 charge to deal an extra 2d10 Necrotic damage to the target and force it to make a DC 15 Constitution saving throw. On a failed save, the target has Disadvantage for 1 hour on any ability check or saving throw that uses Strength or Constitution.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Stone of Controlling Earth Elementals', 'Wondrous Item', NULL, 'Rare', 0, NULL, 'While touching this 5-pound stone to the ground, you can take a Magic action to summon an **Earth Elemental**. The elemental appears in an unoccupied space you choose within 30 feet of yourself, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The stone can\'t be used this way again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Stone of Good Luck (Luckstone)', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'While this polished agate is on your person, you gain a +1 bonus to ability checks and saving throws.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Sun Blade', 'Weapon', 'Longsword', 'Rare (Requires Attunement)', 1, NULL, 'This item appears to be a sword hilt.

_Blade of Radiance._ While grasping the hilt, you can take a Bonus Action to cause a blade of pure radiance to spring into existence or make the blade disappear. While the blade exists, this magic weapon functions as a Longsword with the Finesse property. If you are proficient with Longswords or Shortswords, you are proficient with the _Sun Blade_.

You gain a +2 bonus to attack rolls and damage rolls made with this weapon, which deals Radiant damage instead of Slashing damage. When you hit an Undead with it, that target takes an extra 1d8 Radiant damage.

_Sunlight._ The sword\'s luminous blade emits Bright Light in a 15-foot radius and Dim Light for an additional 15 feet. The light is sunlight. While the blade persists, you can take a Magic action to expand or reduce its radius of Bright Light and Dim Light by 5 feet each, to a maximum of 30 feet each or a minimum of 10 feet each.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Sword of Life Stealing', 'Weapon', 'Glaive, Greatsword, Longsword, Rapier, Scimitar, or Shortsword', 'Rare (Requires Attunement)', 1, NULL, 'When you attack a creature with this magic weapon and roll a 20 on the d20 for the attack roll, that target takes an extra 15 Necrotic damage if it isn\'t a Construct or an Undead, and you gain Temporary Hit Points equal to the amount of Necrotic damage taken.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Sword of Sharpness', 'Weapon', 'Glaive, Greatsword, Longsword, or Scimitar', 'Very Rare (Requires Attunement)', 1, NULL, 'When you attack an object with this magic weapon and hit, maximize your weapon damage dice against the target.

When you attack a creature with this weapon and roll a 20 on the d20 for the attack roll, that target takes an extra 14 Slashing damage and gains 1 Exhaustion level.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Sword of Wounding', 'Weapon', 'Glaive, Greatsword, Longsword, Rapier, Scimitar, or Shortsword', 'Rare (Requires Attunement)', 1, NULL, 'When you hit a creature with an attack using this magic weapon, the target takes an extra 2d6 Necrotic damage and must succeed on a DC 15 Constitution saving throw or be unable to regain Hit Points for 1 hour. The target repeats the save at the end of each of its turns, ending the effect on itself on a success.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Talisman of Pure Good', 'Wondrous Item', NULL, 'Legendary (Requires Attunement by a Cleric or Paladin)', 1, 'by a Cleric or Paladin', 'This talisman is a mighty symbol of goodness. A Fiend or an Undead that touches the talisman takes 8d6 Radiant damage and takes the damage again each time it ends its turn holding or carrying the talisman.

_Holy Symbol._ You can use the talisman as a Holy Symbol. You gain a +2 bonus to spell attack rolls while you wear or hold it.

_Pure Rebuke._ The talisman has 7 charges. While wearing or holding the talisman, you can take a Magic action to expend 1 charge and target one creature you can see on the ground within 120 feet of yourself. A flaming fissure opens under the target, and the target makes a DC 20 Dexterity saving throw. If the target is a Fiend or an Undead, it has Disadvantage on the save. On a failed save, the target falls into the fissure and is destroyed, leaving no remains. On a successful save, the target isn\'t cast into the fissure but takes 4d6 Psychic damage from the ordeal. In either case, the fissure then closes, leaving no trace of its existence. When you expend the last charge, the talisman disperses into motes of golden light and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Talisman of the Sphere', 'Wondrous Item', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'While holding or wearing this talisman, you have Advantage on any Intelligence (Arcana) check you make to control a _Sphere of Annihilation_. In addition, when you start your turn in control of a _Sphere of Annihilation_, you can take a Magic action to move it 10 feet plus a number of additional feet equal to 10 times your Intelligence modifier. This movement doesn\'t have to be in a straight line.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Talisman of Ultimate Evil', 'Wondrous Item', NULL, 'Legendary (Requires Attunement)', 1, NULL, 'This item symbolizes unrepentant evil. A creature that isn\'t a Fiend or an Undead that touches the talisman takes 8d6 Necrotic damage and takes the damage again each time it ends its turn holding or carrying the talisman.

_Holy Symbol._ You can use the talisman as a Holy Symbol. You gain a +2 bonus to spell attack rolls while you wear or hold it.

_Ultimate End._ The talisman has 6 charges. While wearing or holding the talisman, you can take a Magic action to expend 1 charge and target one creature you can see on the ground within 120 feet of yourself. A flaming fissure opens under the target, and the target makes a DC 20 Dexterity saving throw. If the target is a Celestial, it has Disadvantage on the save. On a failed save, the target falls into the fissure and is destroyed, leaving no remains. On a successful save, the target isn\'t cast into the fissure but takes 4d6 Psychic damage from the ordeal. In either case, the fissure then closes, leaving no trace of its existence. When you expend the last charge, the talisman dissolves into foul-smelling slime and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Thunderous Greatclub', 'Weapon', 'Greatclub', 'Very Rare (Requires Attunement)', 1, NULL, 'While you are attuned to this magic weapon, your Strength is 20 unless your Strength is already equal to or greater than that score. The weapon deals an extra 1d8 Thunder damage to any creature it hits and an extra 3d8 Thunder damage to objects it hits that aren\'t being worn or carried.

The weapon has the following additional properties.

_Clap of Thunder._ As a Magic action, you can strike the weapon against a hard surface to create a loud clap of thunder audible out to 300 feet. You also create a 30-foot Cone of thunderous energy. Each creature in the Cone must succeed on a DC 15 Strength saving throw or have the Prone condition. Nonmagical objects in the Cone that aren\'t being worn or carried take 3d8 Thunder damage.

_Earthquake._ As a Magic action, you can strike the weapon against the ground to create an intense seismic disturbance in a 50-foot-radius circle centered on the point of impact. Structures in contact with the ground in that area take 50 Bludgeoning damage, and each creature on the ground in that area must succeed on a DC 20 Dexterity saving throw or have the Prone condition. If that creature is also concentrating, it must succeed on a DC 20 Constitution saving throw, or its Concentration is broken. In addition, you can cause a 30-foot-deep, 10-foot-wide fissure to open up on the ground anywhere in the area. Any creature on a spot where the fissure opens must make a DC 20 Dexterity saving throw, falling into the fissure on a failed save or moving with the fissure\'s edge on a successful one. Any structure on a spot where the fissure opens collapses into the fissure. Once you use this property, it can\'t be used again until the next dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Tome of Clear Thought', 'Wondrous Item', NULL, 'Very Rare', 0, NULL, 'This book contains memory and logic exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book\'s contents and practicing its guidelines, your Intelligence increases by 2, to a maximum of 30. The manual then loses its magic but regains it in a century.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Tome of Leadership and Influence', 'Wondrous Item', NULL, 'Very Rare', 0, NULL, 'This book contains guidelines for influencing and charming others, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book\'s contents and practicing its guidelines, your Charisma increases by 2, to a maximum of 30. The manual then loses its magic but regains it in a century.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Tome of Understanding', 'Wondrous Item', NULL, 'Very Rare', 0, NULL, 'This book contains intuition and insight exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book\'s contents and practicing its guidelines, your Wisdom increases by 2, to a maximum of 30. The manual then loses its magic, but regains it in a century.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Trident of Fish Command', 'Weapon', 'Trident', 'Uncommon (Requires Attunement)', 1, NULL, 'This magic weapon has 3 charges, and it regains 1d3 expended charges daily at dawn. While you carry it, you can expend 1 charge to cast _Dominate Beast_ (save DC 15) from it on a Beast that has a Swim Speed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Universal Solvent', 'Wondrous Item', NULL, 'Legendary', 0, NULL, 'This tube holds milky liquid with a strong alcohol smell. When found, a tube contains 1d6 + 1 ounces.

You can take a Utilize action to pour 1 or more ounces of solvent from the tube onto a surface within reach. Each ounce instantly dissolves up to 1 square foot of adhesive it touches, including _Sovereign Glue_.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Vicious Weapon', 'Weapon', 'Any Simple or Martial', 'Rare', 0, NULL, 'This magic weapon deals an extra 2d6 damage to any creature it hits. This extra damage is of the same type as the weapon\'s normal damage.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Vorpal Sword', 'Weapon', 'Glaive, Greatsword, Longsword, or Scimitar', 'Legendary (Requires Attunement)', 1, NULL, 'You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. In addition, the weapon ignores Resistance to Slashing damage.

When you use this weapon to attack a creature that has at least one head and roll a 20 on the d20 for the attack roll, you cut off one of the creature\'s heads. The creature dies if it can\'t survive without the lost head. A creature is immune to this effect if it has Immunity to Slashing damage, if it doesn\'t have or need a head, or if the GM decides that the creature is too big for its head to be cut off with this weapon. Such a creature instead takes an extra 30 Slashing damage from the hit. If the creature has Legendary Resistance, it can expend one daily use of that trait to avoid losing its head, taking the extra damage instead.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Binding', 'Wand', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This wand has 7 charges.

_Spells._ While holding the wand, you can cast one of the spells (save DC 17) on the following table from it. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Hold Monster*</td>
      <td>5</td>
    </tr>
    <tr>
      <td>*Hold Person*</td>
      <td>2</td>
    </tr>
  </tbody>
</table>

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Enemy Detection', 'Wand', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This wand has 7 charges. While holding it, you can take a Magic action to expend 1 charge. For 1 minute, you know the direction of the nearest creature Hostile to you within 60 feet, but not its distance from you. The wand can sense the presence of Hostile creatures that are Invisible, ethereal, disguised, or hidden, as well as those in plain sight. The effect ends if you stop holding the wand.

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Fear', 'Wand', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This wand has 7 charges.

_Spells._ While holding the wand, you can cast one of the spells (save DC 15) on the following table from it. The table indicates how many charges you must expend to cast the spell.

<table>
  <thead>
    <tr>
      <th>Spell</th>
      <th>Charge Cost</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>*Command* (flee or grovel only)</td>
      <td>1</td>
    </tr>
    <tr>
      <td>*Fear* (60-foot Cone)</td>
      <td>3</td>
    </tr>
  </tbody>
</table>

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Fireballs', 'Wand', NULL, 'Rare (Requires Attunement by a Spellcaster)', 1, 'by a Spellcaster', 'This wand has 7 charges. While holding it, you can expend no more than 3 charges to cast _Fireball_ (save DC 15) from it. For 1 charge, you cast the level 3 version of the spell. You can increase the spell\'s level by 1 for each additional charge you expend.

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Lightning Bolts', 'Wand', NULL, 'Rare (Requires Attunement by a Spellcaster)', 1, 'by a Spellcaster', 'This wand has 7 charges. While holding it, you can expend no more than 3 charges to cast _Lightning Bolt_ (save DC 15) from it. For 1 charge, you cast the level 3 version of the spell. You can increase the spell\'s level by 1 for each additional charge you expend.

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Magic Detection', 'Wand', NULL, 'Uncommon', 0, NULL, 'This wand has 3 charges. While holding it, you can expend 1 charge to cast _Detect Magic_ from it. The wand regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Magic Missiles', 'Wand', NULL, 'Uncommon', 0, NULL, 'This wand has 7 charges. While holding it, you can expend no more than 3 charges to cast _Magic Missile_ from it. For 1 charge, you cast the level 1 version of the spell. You can increase the spell\'s level by 1 for each additional charge you expend.

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Paralysis', 'Wand', NULL, 'Rare (Requires Attunement by a Spellcaster)', 1, 'by a Spellcaster', 'This wand has 7 charges. While holding it, you can take a Magic action to expend 1 charge to cause a thin blue ray to streak from the tip toward a creature you can see within 60 feet of yourself. The target must succeed on a DC 15 Constitution saving throw or have the Paralyzed condition for 1 minute. At the end of each of the target\'s turns, it repeats the save, ending the effect on itself on a success.

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Polymorph', 'Wand', NULL, 'Very Rare (Requires Attunement by a Spellcaster)', 1, 'by a Spellcaster', 'This wand has 7 charges. While holding it, you can expend 1 charge to cast _Polymorph_ (save DC 15) from it.

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Secrets', 'Wand', NULL, 'Uncommon', 0, NULL, 'This wand has 3 charges and regains 1d3 expended charges daily at dawn. While holding it, you can take a Magic action to expend 1 charge, and if a secret door or trap is within 60 feet of you, the wand pulses and points at the one nearest to you.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of the War Mage, +1, +2, or +3', 'Wand', NULL, 'Uncommon (+1), Rare (+2), or Very Rare (+3) (Requires Attunement by a Spellcaster)', 1, 'by a Spellcaster', 'While holding this wand, you gain a bonus to spell attack rolls determined by the wand\'s rarity. In addition, you ignore Half Cover when making a spell attack roll.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Web', 'Wand', NULL, 'Uncommon (Requires Attunement by a Spellcaster)', 1, 'by a Spellcaster', 'This wand has 7 charges. While holding it, you can expend 1 charge to cast _Web_ (save DC 13) from it.

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wand of Wonder', 'Wand', NULL, 'Rare (Requires Attunement)', 1, NULL, 'This wand has 7 charges. While holding it, you can take a Magic action to expend 1 charge while choosing a point within 120 feet of yourself. That location becomes the point of origin of a spell or other magical effect determined by rolling on the Wand of Wonder Effects table. Spells cast from the wand have a save DC of 15. If a spell\'s maximum range is normally less than 120 feet, it becomes 120 feet when cast from the wand. If an effect has multiple possible subjects, the GM determines randomly which among them are affected.

_Regaining Charges._ The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand\'s last charge, roll 1d20. On a 1, the wand crumbles into dust and is destroyed.

**Wand of Wonder Effects**

<table>
  <thead>
    <tr>
      <th>1d100</th>
      <th>Effect</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>01–20</td>
      <td>You cast a spell originating from the chosen point. Roll 1d10 to determine the spell: on a 1–2, Darkness; on a 3–4, Faerie Fire; on a 5–6, Fireball; on a 7–8, Slow; on a 9–10, Stinking Cloud.</td>
    </tr>
    <tr>
      <td>21–25</td>
      <td>Nothing happens at the chosen point of origin. Instead, you have the Stunned condition until the start of your next turn, believing something awesome just happened.</td>
    </tr>
    <tr>
      <td>26–30</td>
      <td>You cast Gust of Wind. The Line created by the spell extends from you to the chosen point of origin.</td>
    </tr>
    <tr>
      <td>31–35</td>
      <td>Nothing happens at the chosen point of origin. Instead, you take 1d6 Psychic damage.</td>
    </tr>
    <tr>
      <td>36–40</td>
      <td>Heavy rain falls for 1 minute in a 120-foot-high, 60-foot-radius Cylinder centered on the chosen point of origin. During that time, the area of effect is Lightly Obscured.</td>
    </tr>
    <tr>
      <td>41–45</td>
      <td>A cloud of 600 oversized butterflies fills a 60-foot-high, 30-foot-radius Cylinder centered on the chosen point of origin. The butterflies remain for 10 minutes, during which time the area of effect is Heavily Obscured.</td>
    </tr>
    <tr>
      <td>46–50</td>
      <td>You cast Lightning Bolt. The Line created by the spell extends from you to the chosen point of origin.</td>
    </tr>
    <tr>
      <td>51–55</td>
      <td>The creature closest to the chosen point of origin is enlarged as if you had cast Enlarge/ Reduce on it. If the target isn\'t you and can\'t be affected by that spell, you become the target instead.</td>
    </tr>
    <tr>
      <td>56–60</td>
      <td>A magically formed creature appears in an unoccupied space as close to the chosen point of origin as possible. The creature isn\'t under your control, acts as it normally would, and disappears after 1 hour or when it drops to 0 Hit Points. Roll 1d4 to determine which creature appears. On a 1, a Rhinoceros appears; on a 2, an Elephant appears; and on a 3–4, a Rat appears.</td>
    </tr>
    <tr>
      <td>61–64</td>
      <td>Grass covers a 60-foot-radius circle of ground, with the center of that circle as close to the chosen point of origin as possible. Grass that\'s already there grows to ten times its normal size and remains overgrown for 1 minute.</td>
    </tr>
  </tbody>
</table>

<table>
  <thead>
    <tr>
      <th>1d100</th>
      <th>Effect</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>65–68</td>
      <td>An object of the GM\'s choice disappears into the Ethereal Plane. The object must be neither worn nor carried, within 120 feet of the chosen point of origin, and no larger than 10 feet in any dimension. If there are no such objects in range, nothing happens.</td>
    </tr>
    <tr>
      <td>69–72</td>
      <td>Nothing happens at the chosen point of origin. Instead, you shrink as if you had cast Enlarge/ Reduce on yourself and remain in that state for 1 minute.</td>
    </tr>
    <tr>
      <td>73–77</td>
      <td>Leaves grow from the creature nearest to the chosen point of origin. Unless they are picked off, the leaves turn brown and fall off after 24 hours.</td>
    </tr>
    <tr>
      <td>78–82</td>
      <td>Nothing happens at the chosen point of origin. Instead, a burst of colorful, shimmering light extends from you in a 30-foot Emanation. Each creature in the area must succeed on a DC 15 Constitution saving throw or have the Blinded condition for 1 minute. A creature repeats the save at the end of each of its turns, ending the effect on itself on a success.</td>
    </tr>
    <tr>
      <td>83–87</td>
      <td>Nothing happens at the chosen point of origin. Instead, you cast Invisibility on yourself.</td>
    </tr>
    <tr>
      <td>88–92</td>
      <td>Nothing happens at the chosen point of origin. Instead, a stream of 1d4 × 10 gems, each worth 1 GP, shoots from the wand\'s tip in a Line 30 feet long and 5 feet wide toward the chosen point of origin. Each gem deals 1 Bludgeoning damage, and the total damage of the gems is divided equally among all creatures in the Line.</td>
    </tr>
    <tr>
      <td>93–97</td>
      <td>You cast Polymorph, targeting the creature closest to the chosen point of origin. Roll 1d4 to determine the target\'s new form. On a 1, the new form is a Black Bear; on a 2, the new form is a Giant Wasp; on a 3–4, the new form is a Frog.</td>
    </tr>
    <tr>
      <td>98–00</td>
      <td>The creature closest to the chosen point of origin makes a DC 15 Constitution saving throw. On a failed save, the creature has the Restrained condition and begins to turn to stone. While Restrained in this way, the creature repeats the save at the end of its next turn. On a successful save, the effect ends. On a failed save, the creature has the Petrified condition instead of the Restrained condition. The petrification lasts until the creature is freed by the Greater Restoration spell or similar magic.</td>
    </tr>
  </tbody>
</table>');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Weapon, +1, +2, or +3', 'Weapon', 'Any Simple or Martial', 'Uncommon (+1), Rare (+2), or Very Rare (+3)', 0, NULL, 'You have a bonus to attack rolls and damage rolls made with this magic weapon. The bonus is determined by the weapon\'s rarity.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Weapon of Warning', 'Weapon', 'Any Simple or Martial', 'Uncommon (Requires Attunement)', 1, NULL, 'As long as this weapon is within your reach and you are attuned to it, you and allies within 30 feet of you gain the following benefits.

_Alarm._ The weapon magically awakens each subject who is sleeping naturally when combat begins. This benefit doesn\'t wake a subject from magically induced sleep.

_Supernatural Readiness._ Each subject has Advantage on its Initiative rolls.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Well of Many Worlds', 'Wondrous Item', NULL, 'Legendary', 0, NULL, 'This fine black cloth, soft as silk, is folded up to the dimensions of a handkerchief. It unfolds into a circular sheet 6 feet in diameter.

You can take a Magic action to unfold the _Well of Many Worlds_ and place it on a solid surface, whereupon it forms a two-way, 6-foot-diameter, circular portal to another world or plane of existence. Each time the item opens a portal, the GM decides where it leads. The portal remains open until a creature within 5 feet of it takes a Magic action to close it by taking hold of the edges of the cloth and folding it up.

Once the _Well of Many Worlds_ has opened a portal, it can\'t do so again for 1d8 hours.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wind Fan', 'Wondrous Item', NULL, 'Uncommon', 0, NULL, 'While holding this fan, you can cast _Gust of Wind_ (save DC 13) from it. Each subsequent time the fan is used before the next dawn, it has a cumulative 20 percent chance of not working; if the fan fails to work, it tears into useless, nonmagical tatters.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Winged Boots', 'Wondrous Item', NULL, 'Uncommon (Requires Attunement)', 1, NULL, 'These boots have 4 charges and regain 1d4 expended charges daily at dawn. While wearing the boots, you can take a Magic action to expend 1 charge, gaining a Fly Speed of 30 feet for 1 hour. If you are flying when the duration expires, you descend at a rate of 30 feet per round until you land.');
INSERT INTO magic_items (name, category, category_detail, rarity, requires_attunement, attunement_requirement, description) VALUES ('Wings of Flying', 'Wondrous Item', NULL, 'Rare (Requires Attunement)', 1, NULL, 'While wearing this cloak, you can take a Magic action to turn the cloak into a pair of wings on your back. The wings lasts for 1 hour or until you end the effect early as a Magic action. The wings give you a Fly Speed of 60 feet. If you are aloft when the wings disappear, you fall. When the wings disappear, you can\'t use them again for 1d12 hours.');
